#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005,mod=998244353;
ll n,m,dep[N],ls[N*32],rs[N*32],tr[N*32],tag[N*32],id[N*32],cnt;//动态开点线段树 数组开大点 总结点数<=nlogn(因为每个update创建<=logn个节点 n个update) 
vector<int> g[N],xianzhi[N];
//tr为线段树所包含的节点的dp之和 
//线段树所包含的节点是l<=dep<=r的节点 （但是是上端点的dep,这也是为什么update,query调用时l=0,r=n,因为上端点dep可能是0） 
void pushup(int u)
{
	tr[u]=(tr[ls[u]]+tr[rs[u]])%mod;
}
void pushdown(int u)
{
	if(tag[u]!=1)
	{
		tr[ls[u]]=tag[u]*tr[ls[u]]%mod;
		tr[rs[u]]=tag[u]*tr[rs[u]]%mod;
		tag[ls[u]]=tag[u]*tag[ls[u]]%mod;
		tag[rs[u]]=tag[u]*tag[rs[u]]%mod;
		tag[u]=1;
	}
}
void update(int l,int r,int pos,ll num,ll  &u)
{
	if(u==0)
	{
		u=++cnt;
		tag[u]=1;
	}
	if(l==r)
	{
		tag[u]=1;
		tr[u]=num;
		return ;
	}
	int mid=(l+r)/2;
	pushdown(u);
	if(pos<=mid) update(l,mid,pos,num,ls[u]);
	else update(mid+1,r,pos,num,rs[u]);
	pushup(u);
}
ll query(int u,int l,int r,int L,int R)
{
	if(L<=l&&R>=r)
	{
		return tr[u];
	}
	int mid=(l+r)/2;
	ll ans=0;
	pushdown(u);
	if(L<=mid) ans=(ans+query(ls[u],l,mid,L,R))%mod;
	if(R>mid) ans=(ans+query(rs[u],mid+1,r,L,R))%mod;
	return ans;
}
ll hebing(int x,int y,int l,int r,ll &sumu,ll &sumv)
{
	if(!x&&!y)
	{
		return 0;
	}
	if(!x)
	{
		sumv=(sumv+tr[y])%mod;
		tag[y]=tag[y]*sumu%mod;
		tr[y]=tr[y]*sumu%mod;
		return y;
	}
	if(!y)
	{
		sumu=(sumu+tr[x])%mod;
		tag[x]=tag[x]*sumv%mod;
		tr[x]=tr[x]*sumv%mod;
		return x;
	}
	if(l==r)
	{
		ll trx=tr[x];
		sumv=(sumv+tr[y])%mod;
		tr[x]=(tr[x]*sumv+tr[y]*sumu)%mod;
		sumu=(sumu+trx)%mod;
		return x;
	}
	ll mid=(l+r)>>1;
	pushdown(x);
	pushdown(y);
	ls[x]=hebing(ls[x],ls[y],l,mid,sumu,sumv);
	rs[x]=hebing(rs[x],rs[y],mid+1,r,sumu,sumv);
	pushup(x);
	return x;
}
void dfs(int u,int f)
{
	dep[u]=dep[f]+1;
	ll mx=0;
	for(int i=0;i<xianzhi[u].size();i++)
	{
		mx=max(mx,dep[xianzhi[u][i]]);
	}
	update(0,n,mx,1,id[u]);
	for(int i=0;i<g[u].size();i++) 
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs(v,u);
		ll tmp1=0,tmp2=query(id[v],0,n,0,dep[u]);
		id[u]=hebing(id[u],id[v],0,n,tmp1,tmp2);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	cin>>m;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		xianzhi[v].push_back(u);
	}
	dfs(1,0);
	cout<<query(id[1],0,n,0,0);
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1200005,mod=998244353;
ll jc[N],ny[N],vis[N],t,n;
ll C(int x,int y)
{
	if((y<0)||(y>x)) return 0;
	return jc[x]*ny[y]%mod*ny[x-y]%mod;
}
void init()
{
	jc[0]=ny[0]=ny[1]=1;
	for(int i=1;i<=N-5;i++) jc[i]=i*jc[i-1]%mod;
	for(int i=2;i<=N-5;i++) ny[i]=(mod-mod/i)*ny[mod%i]%mod;
	for(int i=1;i<=N-5;i++) ny[i]=ny[i]*ny[i-1]%mod;
}
ll fun(int x,int y)
{
	if((x>y)||(y>n)) return 0;
	return (C(2*n-x-y-1,n-x-1)-C(2*n-x-y-1,n-y-2)+mod)%mod;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	init();
	cin>>t;
	while(t--)
	{
		cin>>n;
		memset(vis,0,sizeof(vis));
		ll ans=0,l=1,r=0,flag=0;
		for(int i=1;i<=n;i++)
		{
			int x;
			cin>>x;
			if(flag) continue;
			ans=(ans+fun(i-1,max(r,(ll)x)+1))%mod;
			if((r>x)&&(x>l))
			{
				flag=1;
				continue;
			}
			r=max(r,(ll)x);
			vis[x]=1;
			while(vis[l]) l++;
		}
		cout<<ans<<"\n";
	}
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int t,n,m,cnt;//cnt存dfs序
int dep[N],dfn[N],top[N];//top存这条链（树剖的）的顶端
int son[N],siz[N],fa[N];//son存重儿子
vector<int> g[N];
struct node
{
	int lcol,rcol,cnt;//cnt存线段树该存的
	//(l/r)col : 左/右颜色 
} tr[N*4];
//(备注)这道题记得放剪切板
int laz[N*4];
void clean()
{
	cnt=0;
	for(int i=1;i<=(N-5)*4;i++)
	{
		tr[i].lcol=tr[i].rcol=tr[i].cnt=0;
	}
	for(int i=1;i<=n;i++) g[i].clear();
	memset(laz,0,sizeof(laz));
	memset(siz,0,sizeof(siz));
	memset(fa,0,sizeof(fa));
	memset(dfn,0,sizeof(dfn));
	memset(son,0,sizeof(son));
	memset(top,0,sizeof(top));
	memset(dep,0,sizeof(dep));
}
void push_down(int u,int l,int r)
{
	//把整段(l~r)都染成laz[u]颜色
	if(!laz[u]) return ;
	int mid=(l+r)/2;
	laz[u*2]=laz[u*2+1]=laz[u];
	tr[u*2]=node{laz[u],laz[u],mid-l};//一共有mid-l+1个点都被染成颜色x，所以间隔有mid-l对
	tr[u*2+1]=node{laz[u],laz[u],r-mid-1};//同上
	laz[u]=0;
}
void pushup(int u)
{
	node ls=tr[u*2],rs=tr[u*2+1];
	tr[u]=node{ls.lcol,rs.rcol,ls.cnt+rs.cnt+(ls.rcol==rs.lcol)};
}
void update(int L,int R,int l,int r,int u,int num)//L,R目标区间 l,r当前区间 num表示要染什么颜色
{
	if((L<=l)&&(r<=R))
	{
		tr[u]=node{num,num,r-l};
		laz[u]=num;
		return ;
	}
	push_down(u,l,r);
	int mid=(l+r)/2;
	if(L<=mid) update(L,R,l,mid,u*2,num);
	if(R>mid) update(L,R,mid+1,r,u*2+1,num);
	pushup(u);
}
node query(int L,int R,int l,int r,int u)
{
	if((L<=l)&&(r<=R))
	{
		return tr[u];
	}
	push_down(u,l,r);
	int mid=(l+r)/2,flag=0;
	node ls,rs;
	if(L<=mid) ls=query(L,R,l,mid,u*2),flag++;
	if(R>mid) rs=query(L,R,mid+1,r,u*2+1),flag+=2;
	if(flag==1)
	{
		return ls;
	}
	if(flag==2)
	{
		return rs;
	}
	else
	{
		return node{ls.lcol,rs.rcol,ls.cnt+rs.cnt+(ls.rcol==rs.lcol)};
	}
}
void dfs1(int u,int f)
{
	dep[u]=dep[f]+1;
	fa[u]=f;
	siz[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs1(v,u);
		siz[u]+=siz[v];
		if(siz[v]>siz[son[u]]) son[u]=v;
	}
}
void dfs2(int u)
{
	dfn[u]=++cnt;
	if(son[u])
	{
		top[son[u]]=top[u];
		dfs2(son[u]);
	}
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(fa[u]==v)
		{
			continue;
		}
		if(son[u]==v) continue;
		top[v]=v;
		dfs2(v);
	}
}
void range_update(int x,int y,int num)
{
	while(top[x]!=top[y])
	{
		int tx=top[x],ty=top[y];
		if(dep[tx]<dep[ty])
		{
			swap(x,y);
			swap(tx,ty);
		}
		update(dfn[tx],dfn[x],1,n,1,num);
		x=fa[tx];
	}
	if(dep[x]<dep[y]) swap(x,y);
	update(dfn[y],dfn[x],1,n,1,num);
}
int range_query(int x,int y)//x到y路径上查询 类似lca 要一直跳
{
	bool flag=0;//flag记录在跳的时候 单签跳的是那条边 
	node ans1=node{0,0,0},ans2=node{0,0,0};
	while(top[x]!=top[y])
	{
		int tx=top[x],ty=top[y];
		if(dep[tx]<dep[ty])
		{
			flag=!flag;//这里要注意 因为一直在跳 所以并不是按当前的x和y 按原来的 每次swap 就把flag也取反 
			swap(tx,ty);
			swap(x,y);
		}
		node tmp=query(dfn[tx],dfn[x],1,n,1);
		if(flag)
		{
			ans2=node{tmp.lcol,ans2.rcol,ans2.cnt+tmp.cnt+(ans2.lcol==tmp.rcol)};
		}
		else
		{
			ans1=node{ans1.lcol,tmp.lcol,ans1.cnt+tmp.cnt+(ans1.rcol==tmp.rcol)};//这里要注意：因为为了方便 把ans1的l,r翻了一下 可能不太好理解（太长了看下一行...）
			// 因为是x,y一起往上跳 相当于两条线 为了方便 把ans1的l,r翻了过来 成这样了:
			//                             lca
			//                            /   \
			//                     ans1.rcol    ans2.lcol
			//                        /         \
			//                     ans1.lcol   ans2.rcol
			//         这样最后就方便合并 ：ans1.lcol---ans1.rcol---(lca)（只是为了好理解加上的） ---ans2.lcol---ans2.rcol
			//         注意 tmp的链（代表着当前处理的）永远在ans1/2的上面（tmp.rcol在下 tmp.lcol在上）  就是：
			//             lca
			//            |  \
			//       tmp.lcol \
			//           |     \
			//       tmp.rcol   \
			//          ...    （另外一条线） 
		}
		x=fa[tx];
	}
	if(dep[x]<dep[y])
	{
		swap(x,y);
		flag=!flag;
	}
	node tmp=query(dfn[y],dfn[x],1,n,1);
	if(flag)
	{
		ans2=node{tmp.lcol,ans2.rcol,ans2.cnt+tmp.cnt+(ans2.lcol==tmp.rcol)};
	}
	else
	{
		ans1=node{ans1.lcol,tmp.lcol,tmp.cnt+ans1.cnt+(ans1.rcol==tmp.rcol)};
	}
	return ans1.cnt+ans2.cnt+(ans1.rcol==ans2.lcol);//合并 ：ans1.lcol---ans1.rcol---(lca)（只是为了好理解加上的） ---ans2.lcol---ans2.rcol
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	while(t--)
	{
		clean();
		cin>>n>>m;
		for(int i=1;i<n;i++)
		{
			int u,v;
			cin>>u>>v;
			g[u].push_back(v);
			g[v].push_back(u);
		}
		dfs1(1,0);
		top[1]=1;
		dfs2(1);
		for(int i=1;i<=n;i++) 
		{
			update(dfn[i],dfn[i],1,n,1,dfn[i]+m);//开始时随便赋一个值（互不相同） +m是因为要和询问是的答案互不相同
		}
		for(int i=1;i<=m;i++)
		{
			int op,a,b;
			cin>>op>>a>>b;
			if(op==1) range_update(a,b,i);
			else cout<<range_query(a,b)<<"\n";
		}
	}
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int mod=998244353,N=5005;
ll n,cnt,g[N],jc[N],ny[N],dp[N][N],siz[N][2];
string s;
vector<int> G[N];
ll C(int x,int y)
{
	if((y<0)||(y>x)) return 0;
	return jc[x]*ny[y]%mod*ny[x-y]%mod;
}
void init()
{
	jc[0]=ny[0]=ny[1]=1;
	for(int i=1;i<=N-5;i++) jc[i]=i*jc[i-1]%mod;
	for(int i=2;i<=N-5;i++) ny[i]=(mod-mod/i)*ny[mod%i]%mod;
	for(int i=1;i<=N-5;i++) ny[i]=ny[i]*ny[i-1]%mod;
}
ll sum(int u)
{
	return siz[u][0]+siz[u][1];
}
void dfs(int u,int fa) 
{
	dp[u][0]=1;
	siz[u][0]=(s[u]=='0');
	siz[u][1]=(s[u]=='1');
	for(int i=0;i<G[u].size();i++)
	{
		int v=G[u][i];
		if(fa==v) continue;
		dfs(v,u);
		ll su=sum(u),sv=sum(v);
		for(int i=0;i<su+sv;i++)
		{
			g[i]=0;
		}
		for(int i=0;i<=min(su,n/2);i++)
		{
			for(int j=0;j<=min(sv,n/2-i);j++)
			{
				g[i+j]=(g[i+j]+dp[v][j]*dp[u][i]%mod)%mod;
			}
		}
		for(int i=0;i<su+sv;i++)
		{
			dp[u][i]=g[i];
		}
		siz[u][0]+=siz[v][0];
		siz[u][1]+=siz[v][1];
	}
	for(int i=min(siz[u][0],siz[u][1]);i>=1;i--)
	{
		ll tmp=-i+1;
		if(s[u]=='0') tmp+=siz[u][1];
		else tmp+=siz[u][0];
		dp[u][i]=(dp[u][i]+dp[u][i-1]*tmp%mod)%mod;
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>s;
	s=" "+s;
	for(int i=2;i<=n;i++)
	{
		int u,v;
		cin>>u>>v;
		G[u].push_back(v);
		G[v].push_back(u);
	}
	init();
	dfs(1,0);
	for(int i=0;i<=n/2+1;i++)
	{
		dp[1][i]=(dp[1][i]*jc[n/2-i])%mod;
	}
	for(int i=0;i<=n/2;i++)
	{
		int ans=0;
		for(int j=i;j<=n/2;j++)
		{
			ll tmp=C(j,i)*(((j-i)%2)?mod-1:1)%mod;
//			cout<<C(j,i)<<" "<<tmp<<" "<<dp[1][j]<<"\n";
			ans=(ans+tmp*dp[1][j]%mod)%mod;
		}
		cout<<ans<<"\n";
	}
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2000005,mod=998244353;
ll ny[N],jc[N],t,n,m,num;
ll C(int x,int y)
{
	if((y<0)||(y>x)) return 0;
	return jc[x]*ny[y]%mod*ny[x-y]%mod;
}
void init()
{
	jc[0]=ny[0]=ny[1]=1;
	for(int i=1;i<=N-5;i++) jc[i]=i*jc[i-1]%mod;
	for(int i=2;i<=N-5;i++) ny[i]=(mod-mod/i)*ny[mod%i]%mod;
	for(int i=1;i<=N-5;i++) ny[i]=ny[i]*ny[i-1]%mod;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	init();
	cin>>t;
	while(t--)
	{
		cin>>num;
		n=sqrt(num);
		while(n*(n+1)/2<num) n++;
		m=num-(n*(n-1)/2)-1;
		n--;
		ll ans=0;
		for(int i=0;i<=m;i++)
		{
			int newn=n-i,newm=m-i;
			ans=(ans+(C(newn+newm,newm)-C(newn+newm,newm-1)+mod)%mod*C(newn+newm+i,i)%mod)%mod;
		}
		cout<<ans<<"\n";
	}
	return 0;
}

//f(x,[l,x-1])=f(x,[1,x-1])-f(x,[1,l-1])
//f(a,[l,r])表示a对于[l,r]这个区间的贡献
#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int a[N],block,n,m,k,t[N],pre[N];
ll ans[N];
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	int l,r,id;
	ll ans;
	bool operator<(const node other) const
	{
		if(fun(l)==fun(other.l)) return r<other.r;
		return l<other.l;
	}
} q[N];
struct Node
{
	int l,r,id;//id正 + id负 -
};
vector<Node> v[N];
vector<int> num;//存储__builtin_popcount(i)==k的数字 
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen("P4887_24.in","r",stdin);
//	freopen("a.out","w",stdout);
	cin>>n>>m>>k;
	block=sqrt(n);
	if(k>14)
	{
		for(int i=1;i<=m;i++) cout<<"0\n";
		return 0;
	}
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=m;i++)
	{
		cin>>q[i].l>>q[i].r;
		q[i].id=i;
	}
	sort(q+1,q+1+m);
	for(int i=0;i<(1<<14);i++)
	{
		if(__builtin_popcount(i)==k) num.push_back(i);
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<num.size();j++)
		{
			int tmp=num[j];
			t[a[i]^tmp]++;
		}
		pre[i]=t[a[i+1]];
	}
	memset(t,0,sizeof(t));
	int L=1,R=0;
	for(int i=1;i<=m;i++)
	{
		int l=q[i].l,r=q[i].r;
		if(L<l)
		{
			v[R].push_back(Node{L,l-1,-i});
		}
		while(L<l)
		{
			q[i].ans+=pre[L-1];
			L++;
		}
		if(L>l) v[R].push_back(Node{l,L-1,i});
        while(L>l)
		{
			q[i].ans-=pre[L-2];
			L--;
		}
        if(R<r) v[L-1].push_back(Node{R+1,r,-i});
        while(R<r)
		{
			q[i].ans+=pre[R];
			R++;
		}
        if(R>r) v[L-1].push_back(Node{r+1,R,i});
        while(R>r)
		{
			q[i].ans-=pre[R-1];
			R--;
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<num.size();j++)
		{
			int tmp=num[j];
			t[a[i]^tmp]++;
		}
		for(int j=0;j<v[i].size();j++)
		{
			Node tmp=v[i][j];
			for(int kk=tmp.l;kk<=tmp.r;kk++)
			{
				int tmpp=t[a[kk]];
				if(kk<=i&&k==0) tmpp--;//k=0时 自己^自己也=0 要-1 这里如果脑子一抽可能想成/2（虽然不太可能）
									   //配对是与前面的数配对 就是前面的数t[前面的数^tmp]++ 而 前面的数^tmp 正好是当前数 就配成对了 因为这时前面的数^当前数=num里的一个数字（就是 __builtin_popcount(i)==k）
				q[abs(tmp.id)].ans+=(((tmp.id>0)?1:-1)*tmpp);
			}
		}
	}
	for(int i=1;i<=m;i++)
	{
		q[i].ans+=q[i-1].ans;
		ans[q[i].id]=q[i].ans;
	}
	for(int i=1;i<=m;i++) cout<<ans[i]<<"\n";
	return 0;
}

