//如果你要查询的范围有：
// 1个1 2个2 0个3 1个4 那bitset为 10（这部分是因为有1个1）110（因为2个2）00(因为0个3）10（因为1个4）
//这样 你会发现只要将3个bitset进行&操作，再看看里面要多少个1 就知道答案了
const int N=100005,M=20005;
int a[N],n,m,b[N],s[N],vis[N],len[N],block;
bitset<N> ans[M],bs;
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	int l,r,id;
	bool operator<(const node other) const
	{
		if(fun(other.l)==fun(l)) return r<other.r;
		return l<other.l;
	}
} q[N];
void update(int x,int y)
{
	int tmp=a[x];
	if(y==-1)
	{
		bs[tmp+(--s[tmp])]=0;
	}
	else bs[tmp+(s[tmp]++)]=1;
}
void solve(int x)
{
//	cout<<x<<"---\n";
	ll cnt=0;
	memset(s,0,sizeof(s));
	for(int i=1;i<=x;i++)
	{
		vis[i]=len[i]=0;
		for(int j=1;j<=3;j++)
		{
			q[++cnt].id=i;
			cin>>q[cnt].l>>q[cnt].r;
			len[i]+=(q[cnt].r-q[cnt].l+1);
		}
	}
	sort(q+1,q+1+cnt);
	ll L=1,R=0;
	bs=0;
	for(int i=1;i<=cnt;i++)
	{
		int l=q[i].l,r=q[i].r;
		while(L>l) update(--L,1);
		while(R<r) update(++R,1);
		while(L<l) update(L++,-1);
		while(R>r) update(R--,-1);
		if(vis[q[i].id]) ans[q[i].id]&=bs;
		else ans[q[i].id]=bs;
		vis[q[i].id]=1;
	}
	for(int i=1;i<=x;i++)
	{
//		cout<<i<<" ii\n";
		cout<<len[i]-3*ans[i].count()<<"\n";
	}
}
