#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int head[N],nxt[N*2],val[N*2],tot;
void add(int u,int v)
{
	val[++tot]=v;
	nxt[tot]=head[u];
	head[u]=tot; 
}
int n,m;
const int M=N*80;
int tre[M],sum[M],sl[M],sr[M],cnt;
void push_up(int x){
    if(sl[x]==0){
        sum[x]=sum[sr[x]];
        tre[x]=tre[sr[x]];
        return;
    }
    if(sr[x]==0){
        sum[x]=sum[sl[x]];
        tre[x]=tre[sl[x]];
        return;
    }
    if(sum[sl[x]]>=sum[sr[x]]){
        sum[x]=sum[sl[x]];
        tre[x]=tre[sl[x]];
    }else{
        sum[x]=sum[sr[x]];
        tre[x]=tre[sr[x]];
    }
}
void change(int &x, int l, int r, int pos, int val){
    if(x==0) x=++cnt;
    if(l==r){
        sum[x]+=val;
        tre[x]=pos;
        return;
    }
    int mid=(l+r)>>1;
    if(pos<=mid) change(sl[x], l, mid, pos, val);
    else change(sr[x], mid+1, r, pos, val);
    push_up(x);
}
int merge(int a, int b, int l, int r){
    if(a==0||b==0) return a+b;
    if(l==r){
        sum[a]+=sum[b];
        return a;
    }
    int mid=(l+r)>>1;
    sl[a]=merge(sl[a], sl[b], l, mid);
    sr[a]=merge(sr[a], sr[b], mid+1, r);
    push_up(a);
    return a;
}
int f[N][30],dep[N];
void dfs(int u,int fa)
{
	f[u][0]=fa;
	dep[u]=dep[fa]+1;
	for(int i=1;f[u][i-1];i++)
	{
		f[u][i]=f[f[u][i-1]][i-1];
	}
	for(int i=head[u];i;i=nxt[i])
	{
		int v=val[i];
		if(v==fa) continue;
		dfs(v,u);
	}
}
int lca(int a,int b)
{
	if(dep[a]<dep[b]) swap(a,b);
	int k=log2(dep[a]);
	for(int i=k;i>=0;i--)
	{
		if(dep[f[a][i]]>=dep[b]) a=f[a][i];
	}
	if(a==b) return a;
	for(int i=k;i>=0;i--)
	{
		if(f[a][i]!=f[b][i]) a=f[a][i],b=f[b][i];
	}
	return f[a][0];
}
int num[N],ans[N];
void prepare(int u,int fa)
{
	for(int i=head[u];i;i=nxt[i])
	{
		int v=val[i];
		if(v==fa) continue;
		prepare(v,u);
		num[u]=merge(num[u],num[v],1,N); 
	}
	ans[u]=tre[num[u]];
	if(sum[num[u]]==0) ans[u]=0;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<n;i++)
	{
		int a,b;
		cin>>a>>b;
		add(a,b);
		add(b,a);
	}
	dfs(1,0);
	for(int i=1;i<=m;i++)
	{
		int a,b,c;
		cin>>a>>b>>c;
		int l=lca(a,b);
		change(num[a],1,N,c,1);
		change(num[b],1,N,c,1);
		change(num[l],1,N,c,-1);
		change(num[f[l][0]],1,N,c,-1);
	}
	prepare(1,0);
	for(int i=1;i<=n;i++) cout<<ans[i]<<'\n';
	return 0;
}

