const int N=40565;
int t,k,p[N],num[N];
/*
对于正整数 i：
num[i] = 1：当 i = 1 时
num[i] = (-1)^k：当 i 是 k 个不同质数的乘积时（即 i 无平方因子，且质因子个数为 k）
num[i] = 0：当 i 含有平方因子时（即存在某个质数 p，使得 p2 能整除 i）
*/
bool vis[N];
void init()
{
	int cnt=0;
	num[1]=1;
	for(int i=2;i<=40560;++i)
	{
		if(!vis[i])
		{
			p[++cnt]=i;
			num[i]=-1;
		}
		for(int j=1;(j<=cnt)&&(i*p[j])<=40560;j++)
		{
			vis[i*p[j]]=true;
			if(i%p[j]) num[i*p[j]]=-num[i];
			else break;
		}
	}
}
bool check(int x)
{
	int ans=0;
	for(int i=1;i*i<=x;++i)
	{
		ans+=num[i]*(x/(i*i));
	}
	return ans>=k;
}
