#define ll long long
const int N=55;
int n,a,b,mx[N][N],mn[N][N],ans1,ans2,ans3;
void floyd()
{
	for(int k=1;k<=n;k++)
	{
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=n;j++)
			{
				mx[i][j]=min(mx[i][j],mx[i][k]+mx[k][j]);
				mn[i][j]=max(mn[i][j],mn[i][k]+mn[k][j]);
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
