	{
		string s;
		cin>>s;
		s=" "+s;
		for(int j=1;j<=n;j++)
		{
			char c=s[j];
			if((i==j)||(c=='=')) mx[i][j]=mn[i][j]=0;
			else if(c=='+') mx[i][j]=2,mn[i][j]=1;
			else if(c=='-') mx[i][j]=-1,mn[i][j]=-2;
			else mx[i][j]=2,mn[i][j]=-2;
		}
	}
