			(mn[b][i]==mx[b][i]&&mn[b][i]==mn[j][a]&&mn[j][a]==mx[j][a])) ans2++;
			if((mx[a][i]<mn[j][b])||(mx[a][j]<mn[i][b])) ans3++;
		}
	}
	cout<<ans1<<" "<<ans2<<" "<<ans3;
	return 0;
}

