			mxnum=i;
		}
	}
	for(int i=1;i<=n*2;i++)
	{
		for(int j=1;j<=n*2;j++) 
		{
			dp[i][j][0]=dp[i][j][1]=1e18;
		}
	}
	dp[mxnum][mxnum][0]=dp[mxnum][mxnum][1]=dp[mxnum+n][mxnum+n][0]=dp[mxnum+n][mxnum+n][1]=0;
	for(int len=2;len<=n;len++)
	{
		for(int l=1,r=len;r<=n*2;l++,r++)
		{
			db tmp1=dp[l+1][r][0]+fun(l+1,l),tmp2=dp[l+1][r][1]+fun(r,l);
			if(tmp1<tmp2)
			{
				dp[l][r][0]=tmp1;
				pre[l][r][0]=0;
			}
			else
			{
				dp[l][r][0]=tmp2;
				pre[l][r][0]=1;
			}
			tmp1=dp[l][r-1][0]+fun(l,r),tmp2=dp[l][r-1][1]+fun(r-1,r);
			if(tmp1<tmp2)
			{
				dp[l][r][1]=tmp1;
				pre[l][r][1]=0;
			}
			else
			{
				dp[l][r][1]=tmp2;
				pre[l][r][1]=1;
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		if(dp[i][i+n-1][0]<ans)
		{
			ans=dp[i][i+n-1][0];
			ansl=i;
			ansr=i+n-1;
			ansop=0;
		}
		if(dp[i][i+n-1][1]<ans)
		{
			ans=dp[i][i+n-1][1];
