		}
		else
		{
			v.push_back(ansr);
			ansop=pre[ansl][ansr][1];
			ansr--;
		}
	}
	v.push_back(ansl);
	for(int i=v.size()-1;i>=0;i--)
	{
		cout<<(v[i]-1)%n+1<<" ";
	}
	return 0;
}

