const int N=1000005,mod=1e9+7;
ll n,a[N],jc[N];
ll qp(ll x,ll y)
{
    ll ans=1;
    while(y)
    {
        if(y%2) ans=(ans*x)%mod;
        x=(x*x)%mod;
        y/=2;
    }
    return ans;
}
ll c(ll x,ll y)
{
    return jc[x]*qp((jc[x-y]%mod)*jc[y]%mod,mod-2)%mod;
}
ll ans=1;
void init()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
