int vis[N];// for topo
void topo1()
{
	queue<int> q;
	for(int i=0;i<=m;i++)
	{
		vis[i]=fan[i].size();
		if(vis[i]==0) q.push(i);
	}
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i];
//			cout<<u<<" -> "<<v<<"  "<<b[u]<<"\n";
			b[v]=b[v]*b[u]%mod;
			vis[v]--;
			if(vis[v]==0) q.push(v);
		}
	}

}

void topo2()
{
	queue<int> q;
	for(int i=0;i<=m;i++)
	{
		vis[i]=g[i].size();
		if(vis[i]==0) q.push(i);
	}
	while(!q.empty())
	{
		ll tmp=1;
		int u=q.front();
		q.pop();
		for(int i=fan[u].size()-1;i>=0;i--)
		{
			int v=fan[u][i];
			cnt[v]=(cnt[v]+cnt[u]*tmp)%mod;
			tmp=tmp*b[v]%mod;
			vis[v]--;
			if(vis[v]==0) q.push(v);
		}
	}
}
