#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2000005,mod=998244353;
ll n,k,ans,pos[N],jc[N],ny[N];
string s;
ll C(int x,int y)
{
	if((y<0)||(y>x)) return 0;
	return jc[x]*ny[y]%mod*ny[x-y]%mod;
}
void init()
{
	jc[0]=ny[0]=ny[1]=1;
	for(int i=1;i<=N-5;i++) jc[i]=i*jc[i-1]%mod;
	for(int i=2;i<=N-5;i++) ny[i]=(mod-mod/i)*ny[mod%i]%mod;
	for(int i=1;i<=N-5;i++) ny[i]=ny[i]*ny[i-1]%mod;
	stack<int> st;
	for(int i=1;i<=n;i++)
	{
		if(s[i]=='(')
		{
			st.push(i);
		}
		else
		{
			if(st.empty()) continue;
			pos[i]=st.top();
			pos[st.top()]=i;
			st.pop();
		}
	}
	while(!st.empty())
	{
		pos[st.top()]=n+1;
		st.pop();
	}
}
ll fun(ll x)
{
	return C(x+k,x-1);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>k>>s;
	s=" "+s;
	k--;
	init();
	for(int i=1;i<=n;i++)
	{
		if(s[i]=='(')
		{
			ans+=(fun(i)*(fun(n-i+1)-fun(n-pos[i]+1)+mod)%mod)%mod;
			ans%=mod;
		}
		else
		{
			ans+=(fun(n-i+1)*(fun(i)-fun(pos[i])+mod)%mod)%mod;
			ans%=mod;
		}
	}
	cout<<ans;
	return 0;
}

