#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005;
int n,q,son[N],op[N],dep[N],fa[N][35];//op为在1这个根节点上哪个儿子的后代 
vector<int> g[N];
void dfs1(int u,int f,int flag)
{
	dep[u]=dep[f]+1;
	op[u]=flag;
	son[u]=1;
	fa[u][0]=f;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		if(flag==0) flag=v;
		dfs1(v,u,flag);
		if(flag==v) flag=0;
		son[u]+=son[v];
	}
}
int check(int x,int y)
{
	for(int i=log2(n);i>=0;i--)
	{
		if(dep[fa[x][i]]>dep[y]) x=fa[x][i];
	}
	if(fa[x][0]!=y) return 0;
	return x;
}
int lca(int x,int y)
{
	if(dep[y]<dep[x]) swap(x,y);
	int k=log2(dep[y])+1;
	for(int i=k;i>=0;i--)
	{
		if((dep[y]-(1<<i))>=dep[x]) y=fa[y][i];
	}
	if(x==y) return x;
	for(int i=k;i>=0;i--)
	{
		if(fa[x][i]&&fa[x][i]!=fa[y][i])
		{
			x=fa[x][i];
			y=fa[y][i];
		}
	}
	return fa[x][0];
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen("P6374_6.in","r",stdin);
//	freopen("my.out","w",stdout);
	cin>>n>>q;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dfs1(1,0,0);
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			fa[j][i]=fa[fa[j][i-1]][i-1];
		}
	}
	while(q--)
	{
		int a,b,c;
		cin>>a>>b>>c;
		if(a==b)
		{
			if(b==c)
			{
				cout<<n<<"\n";
				continue;
			}
			cout<<"0\n";
			continue;
		}
		if(b==c) swap(a,b);
		if(a==c)
		{
			int tmp=check(b,a);
			if(tmp)
			{
				cout<<n-son[tmp]<<"\n";
				continue;
			}
			cout<<son[a]<<"\n";
			continue;
		}
		if(c==1)
		{
			if(lca(a,b)!=c)
			{
				cout<<"0\n";
				continue;
			}
			int ans=n-son[op[a]]-son[op[b]];
			if(op[a]==op[b])
			{
				ans+=son[op[a]];
			}
			cout<<ans<<"\n";
			continue;
		}
		int opa=op[a],opb=op[b],opc=op[c];
		if((opa!=opc)&&(opb!=opc))
		{
			cout<<"0\n";
			continue;
		}
		if(opa==opb)
		{
			if(dep[a]>dep[b]) swap(a,b);
			int checkba=check(b,a),checkac=check(a,c),checkbc=check(b,c);
			if(checkba&&checkac)
			{
				cout<<"0\n";
				continue;
			}
			if(lca(a,b)!=c)
			{
				if(checkac)
				{
					if(checkbc)
					{
						cout<<"0\n";
						continue;
					}
					cout<<son[c]-son[checkac]<<"\n";
					continue;
				}
				if(checkbc)
				{
					cout<<son[c]-son[checkbc]<<"\n";
					continue;
				}
				cout<<"0\n";
				continue;
			}
			if(checkba)
			{
				cout<<n-son[c]+1<<"\n";
				continue;
			}
			cout<<n-son[checkac]-son[check(b,c)]<<"\n";
			continue;
		}
		if(opb==opc)
		{
			swap(a,b);
			swap(opa,opb);
		}
		if(dep[c]>=dep[a])
		{
			cout<<"0\n";
			continue;
		}
		int tmp=check(a,c);
		if(!tmp)
		{
			cout<<"0\n";
			continue;
		}
		cout<<son[fa[tmp][0]]-son[tmp]<<"\n";
	}
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
const int N=1005;
int n,m,q,dis[N];
vector<int> g[N];
bitset<N> bs[N][N];
void bfs(int u)
{
	queue<int> q;
	memset(dis,0x3f,sizeof(dis));
	q.push(u);
	dis[u]=0;
	while(!q.empty())
	{
		int tmp=q.front();
		q.pop();
		for(int i=0;i<g[tmp].size();i++)
		{
			int v=g[tmp][i];
			if(dis[v]>dis[tmp]+1)
			{
				dis[v]=dis[tmp]+1;
				q.push(v);
			}
		}
	}
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n>>m>>q;
	while(m--)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	for(int i=1;i<=n;i++)
	{
		bfs(i);
		for(int j=1;j<=n;j++)
		{
			if(dis[j]!=0x3f3f3f3f) bs[i][dis[j]][j]=1;
		}
		for(int j=1;j<=n;j++) bs[i][j]|=bs[i][j-1];
	}
	while(q--)
	{
		bitset<N> ans;
		int num;
		cin>>num;
		while(num--)
		{
			int x,y;
			cin>>x>>y;
			ans|=bs[x][y];
		}
		cout<<ans.count()<<'\n';
	}
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
ll l,r,len,num[35],dp[35][35][35];
/*
x  第几位 从个位到高位（dfs是从高位到个位的）
cnt0 0的个数
cnt1 1的个数 
limit 是否受到最大值的限制 
beg0 （1代表前面出现过非0数字 ，0代表前面全是前导0） 
*/
ll dfs(ll x,ll cnt0,ll cnt1,ll limit,ll beg0)
{
	if(!x) return (cnt0>=cnt1);
	if((!limit)&&beg0&&(dp[x][cnt0][cnt1]!=-1)) return dp[x][cnt0][cnt1];
	int mx=(limit)?num[x]:1;
	ll cnt=0;
	for(int i=0;i<=mx;i++)
	{
		ll ncnt0=cnt0,ncnt1=cnt1;
		if(beg0||(i==1))
		{
