{
    if(num)
    {
        visl[a[L+1]]++;
        ans+=visr[a[L+1]];
        L++;
        return ;
    }
    visl[a[L]]--;
    ans-=visr[a[L]];
    L--;
}
void mr(int num)
{
    if(num)
    {
        visr[a[R+1]]++;
        ans+=visl[a[R+1]];
        R++;
        return ;
    }
    visr[a[R]]--;
    ans-=visl[a[R]];
    R--;
}
