{
	int tr[N][N];
	void add(int x,int y,int z)
	{
		for(int i=x;i<=n;i+=(i&(-i)))
		{
			for(int j=y;j<=m;j+=(j&(-j)))
			{
				tr[i][j]+=z;
			}
		}
	}
	int query(int x,int y)
	{
		int sum=0;
		for(int i=x;i;i-=(i&-i))
		{
			for(int j=y;j;j-=(j&(-j)))
			{
				sum+=tr[i][j];
			}
		}
		return sum;
	}
}a,b,c,d;
int fun(int x,int y)
{
	return a.query(x,y)*(x*y+x+y+1)
			-b.query(x,y)*(y+1)
			-c.query(x,y)*(x+1)
			+d.query(x,y);
}
void fun2(int x,int y,int z)
{
	a.add(x,y,z);
	b.add(x,y,z*x);
	c.add(x,y,z*y);
	d.add(x,y,z*x*y);
}
