struct node
{
    int l,r,id;
} q[N];
bool cmp(node a,node b)
{
    if(id[a.l]==id[b.l]) return a.r<b.r;
    return  a.l<b.l;
}
void add(int x)
{
    sum+=cnt[a[x]^k];
    cnt[a[x]]++;
}
void del(int x)
{
    cnt[a[x]]--;
    sum-=cnt[a[x]^k];
}
