/*
x  第几位 从个位到高位（dfs是从高位到个位的）
pre 上一个数字 
prcnt 上一个数字持续了多少
flg 有没有数字持续了3次 
flg4 4出现了没有 
flg8 8出现了没有 
limit 是否受到最大值的限制 
beg0 （1代表前面出现过非0数字 ，0代表前面全是前导0）
*/
ll dfs(ll x,ll pre,ll prcnt,ll flg,ll flg4,ll flg8,ll limit,ll beg0)
{
	if(!x) return flg;
	if((!limit)&&beg0&&(dp[x][pre][prcnt][flg][flg4][flg8]!=-1)) return dp[x][pre][prcnt][flg][flg4][flg8];
	int mx=(limit)?num[x]:9;
	ll cnt=0;
	for(int i=0;i<=mx;i++)
	{
		ll nflg4=(i==4)||flg4,nflg8=flg8||(i==8);
		if(nflg4&&nflg8) continue;
		ll tmp=prcnt;
		if(beg0&&(i==pre)) prcnt++;
		else prcnt=1;
		cnt+=dfs(x-1,i,prcnt,flg||(prcnt>2),nflg4,nflg8,limit&&(i==mx),beg0||i);
		prcnt=tmp;
	}
	if((!limit)&&beg0) dp[x][pre][prcnt][flg][flg4][flg8]=cnt;
	return cnt;
}
ll solve(ll x)
{
//	int len;
	for(len=1;x;x/=10,len++)
	{
		num[len]=x%10;
	}
	return dfs(len-1,0,0,0,0,0,1,0);//这里pre随便选一个数就行 
}
