ll manacher(string ss)
{
	string s="  ";
	for(int i=0;i<ss.size();i++)
	{
		s+=ss[i];
		s+=" ";
	}
	n=s.size()-1;
	mx=mid=0;
	ll ans=0;
	for(int i=1;i<n;i++)
	{
		if(mx>i)
		{
			len[i]=min(len[2*mid-i],mx-i);
		}
		else len[i]=0;
		while(s[i+len[i]+1]==s[i-len[i]-1])
		{
			len[i]++;
		}
		if(i+len[i]>mx)
		{
			mx=i+len[i];
			mid=i;
		}
		ans=(ans+(len[i]+1)/2)%mod;
	}
	return ans;
}
