#include <bits/stdc++.h>
using namespace std;
const int N=500005;
int tim,dfn[N],low[N],cnt,vis[N],n,m,vis2[N],vis3[N],a[N],flag[N],ans,s,s2,p,dp[N],fir[N],from[N],to[N],cnt2,fir2[N],from2[N],to2[N],cnt3;
stack<int> st;
bool flag2[N];
void add(int a,int b)
{
    from[++cnt2]=fir[a];
    fir[a]=cnt2; to[cnt2]=b;
}
void add2(int a,int b)
{
    from2[++cnt3]=fir2[a];
    fir2[a]=cnt3; to2[cnt3]=b;
}
void tarjan(int u)
{
	dfn[u]=low[u]=++tim;
	st.push(u);
	for(int i=fir[u];i;i=from[i])
    {
		int v=to[i];
		if(dfn[v]==0)
        {
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v]==0)
        {
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
    {
		cnt++;
		while(true)
        {
			int now=st.top();
			st.pop();
			vis[now]=cnt;
            vis2[cnt]+=a[now];
            if(now==s) s2=cnt;
            if(flag[now]) vis3[cnt]=1;
			if(now==u) break;
		}
	}
}
void topo()
{
	queue<int> q;
    q.push(s2);
    while(!q.empty())
    {
        int v=q.front();
        q.pop();
        flag2[v]=0;
        if(v==s2) dp[v]=vis2[v];
        for(int i=fir2[v];i;i=from2[i])
        {
            int j=to2[i];
            if(flag2[j]==0)
            {
                q.push(j);
                flag2[j]=1;
            }
            dp[j]=max(dp[j],dp[v]+vis2[j]);
        }
        if(vis3[v]) ans=max(ans,dp[v]);
    }
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=m;i++)
    {
        int u,v;
        cin>>u>>v;
        add(u,v);
    }
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    cin>>s>>p;
    for(int i=1;i<=p;i++)
    {
        int x;
        cin>>x;
        flag[x]=1;
    }
	tarjan(s);
	for(int u=1;u<=n;u++)
    {
        if(vis[u]==0) continue;
		for(int i=fir[u];i;i=from[i])
        {
            int j=to[i];
            if(vis[j]==0) continue;
			if(vis[u]!=vis[j])
            {
                add2(vis[u],vis[j]);
			}
		}
	}
    topo();
    cout<<ans;
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
const int N=200005,INF=1e9+5;
vector<int> v;
map<int,int> mp;
int log_n,n,pos[2*N],nxt[N][20],mn[2*N];
struct node
{
    int l,r,id;
} a[N];
struct Node
{
    int num,id;
    bool operator<(const Node other) const
    {
        return num<other.num;
    }
};
bool cmp1(node x,node y)
{
    return x.l<y.l;
}
bool cmp2(node x,node y)
{
    return x.id<y.id;
}
int fun(int l,int r)
{
    int ans=0;
    for(int i=log_n;i>=0;i--)
    {
        if(a[nxt[l][i]].r<=r)
        {
            ans+=(1<<i);
            l=nxt[l][i];
        }
    }
    return ans;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    log_n=log2(n);
    for(int i=1;i<=n;i++)
    {
        int l,r;
        cin>>l>>r;
        v.push_back(l);
        v.push_back(r);
        a[i]=node{l,r,i};
    }
    sort(v.begin(),v.end());
    int len=unique(v.begin(),v.end())-v.begin()-1;
    for(int i=0;i<=len;i++)
    {
        mp[v[i]]=i+1;
    }
    len++;
    for(int i=1;i<=n;i++)
    {
        a[i].l=mp[a[i].l];
        a[i].r=mp[a[i].r];
    }
    sort(a+1,a+1+n,cmp1);
    a[n+1]=node{INF,INF,n+1},a[0]=node{-INF,-INF,0};
    memset(mn,0x3f,sizeof(mn));
    mn[len+1]=len+1;
    pos[len+1]=n+1;
    for (int i=n;i>=1;i--)
    {
        if(mn[a[i].l]>a[i].r)
        {
            mn[a[i].l]=a[i].r,pos[a[i].l]=a[i].id;
        }
    }
    for(int i=len;i>=1;i--)
    {
        if(mn[i]>mn[i+1])
        {
            mn[i]=mn[i+1],pos[i]=pos[i+1];
        }
    }
    nxt[n+1][0]=n+1;
    for(int i=1;i<=n;i++)
    {
        nxt[a[i].id][0]=pos[a[i].r+1];
    }
    nxt[0][0]=pos[1];
    for(int i=1;i<=log_n;i++)
    {
        for(int j=0;j<=n+1;j++)
        {
            nxt[j][i]=nxt[nxt[j][i-1]][i-1];
        }
    }
    sort(a+1,a+1+n,cmp2);
    int ans1=fun(0,INF-1);
    cout<<ans1<<"\n";
    set<Node> s;
    s.insert(Node{-INF,0}),s.insert(Node{INF,n+1});
    for(int i=1;i<=n;i++)
    {
        auto it=s.upper_bound(Node{a[i].r,0});
        auto it2=s.upper_bound(Node{a[i].l,0});
        if(it!=it2) continue;
        Node rr=*it;
        it--;
        Node ll=*it;
        if(fun(ll.id,a[i].l-1)+fun(i,rr.num-1)+1!=fun(ll.id,rr.num-1)) continue;
        cout<<i<<" ";
        s.insert(Node{a[i].l,a[i].id});
        s.insert(Node{a[i].r,a[i].id});
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define ull unsigned long long
const long long N=500005,base=2333;
string s;
ull n,a[N],ans,b[N],t[N];
bool check(int l,int mid)
{
	int r=mid+(mid-l)+1;
	ull num1=a[mid]-a[l-1]*t[mid-l+1],num2=b[mid+1]-b[r+1]*t[mid-l+1];
	if(num1==num2)
	{
		return 1;
	}
	return 0;
}
int main()
{
	cin>>n>>s;
	s=" "+s;
	t[0]=1;
	for(int i=1;i<=n;i++)
	{
		t[i]=t[i-1]*base;
		a[i]=(a[i-1]*base+(s[i]-'0'));
	}
	for(int i=n;i>=1;i--)
	{
		b[i]=(b[i+1]*base+!(s[i]-'0'));
	}
	for(int i=1;i<n;i++)
	{
		int l=max(i-(int)n+i+1,1),r=i,mid;
		while(l<=r)
		{
			mid=(l+r)/2;
			if(check(mid,i))
			{
				r=mid-1;
			}
			else l=mid+1;
		}
		ans+=(i-r);
	}
	cout<<ans;
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=800005;
int tr[N],tag[N],num[N]; // 线段树 
int n,m,r,p,w[N]; //输入
int id[N],fa[N],cnt,dep[N],siz[N];
int zson[N],top[N];//树链 
vector<int> g[N];
void pushup(int id)
{
	tr[id]=(tr[id<<1]+tr[(id<<1)|1])%p;
}
void pushdown(int id,int len)
{
	int ls=id<<1,rs=id<<1|1;
	tag[ls]+=tag[id];
	tag[rs]+=tag[id];
	tr[ls]+=tag[id]*(len-(len>>1));
	tr[rs]+=tag[id]*(len>>1);
	tr[ls]%=p;
	tr[rs]%=p;
	tag[id]=0;
}
void build(int id,int l,int r)
{
	if(l==r)
	{
		tr[id]=num[l];
		tr[id]%=p;
		return ;
	}
	int mid=(l+r)>>1;
	build(id<<1,l,mid);
	build(id<<1|1,mid+1,r);
	pushup(id);
}
int query(int id,int l,int r,int x,int y)
{
	if(x<=l&&y>=r)
	{
		return tr[id]; 
	}
	int mid=(l+r)>>1;
	if(tag[id]) pushdown(id,r-l+1);
	int sum=0;
	if(x<=mid) sum+=query(id<<1,l,mid,x,y);
	if(y>mid) sum+=query(id<<1|1,mid+1,r,x,y);
	return sum%p;
}
void update(int id,int l,int r,int x,int y,int k)
{
	if(x<=l&&y>=r)
	{
		tag[id]+=k;
		tr[id]+=k*(r-l+1);
		return ;
	}
	int mid=(l+r)>>1;
	if(tag[id]) pushdown(id,r-l+1);
	if(x<=mid) update(id<<1,l,mid,x,y,k);
	if(y>mid) update(id<<1|1,mid+1,r,x,y,k);
	pushup(id);
}
int lian_query(int x,int y)
{
	int sum=0;
	while(top[x]!=top[y])
	{
		if(dep[top[x]]<dep[top[y]]) swap(x,y);
		sum=(sum+query(1,1,n,id[top[x]],id[x]))%p;
		x=fa[top[x]];
	}
	if(dep[x]>dep[y]) swap(x,y);
	sum=(sum+query(1,1,n,id[x],id[y]))%p;
	return sum;
}
void lian_update(int x,int y,int k)
{
	k%=p;
	while(top[x]!=top[y])
	{
		if(dep[top[x]]<dep[top[y]]) swap(x,y);
		update(1,1,n,id[top[x]],id[x],k);
		x=fa[top[x]];
	}
	if(dep[x]>dep[y]) swap(x,y);
	update(1,1,n,id[x],id[y],k);
}
void dfs1(int u,int f,int depp)
{
//	cout<<"--- dfs1 : "<<u<<" "<<f<<' '<<depp<<"\n";
	dep[u]=depp;
	fa[u]=f;
	siz[u]=1;
	int mx=-1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs1(v,u,depp+1);
		siz[u]+=siz[v];
//		cout<<v<<" siz : "<<siz[v]<<"\n";
		if(siz[v]>mx) zson[u]=v,mx=siz[v];
	}
}
void dfs2(int u,int numm)
{
//	cout<<u<<"  ----dfs2\n";
	id[u]=++cnt;
	num[cnt]=w[u];
	top[u]=numm;
//	cout<<"zson ? \n";
	if(!zson[u])
	{
//		cout<<"   return ;\n";
		return ;
	}
//	cout<<"Yes!\n";
	dfs2(zson[u],numm);
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==fa[u]||v==zson[u]) continue;
		dfs2(v,v);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>r>>p;
	for(int i=1;i<=n;i++) cin>>w[i];
	for(int i=1;i<n;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(y);
		g[y].push_back(x);
	}
	dfs1(r,0,1);
	dfs2(r,r);
//	cout<<"aaa"<<endl;
	build(1,1,n);
//	cout<<"bbb"<<endl<<"id : ";
//	for(int i=1;i<=n;i++) cout<<id[i]<<" ";
//	cout<<"\n";
	while(m--)
	{
//		cout<<"---"<<m<<endl;
		int k,x,y,z;
		cin>>k;
		if(k==1)
		{
			cin>>x>>y>>z;
			lian_update(x,y,z);
		}
		else if(k==2)
		{
			cin>>x>>y;
			cout<<lian_query(x,y)<<'\n';
		}
		else if(k==3)
		{
			cin>>x>>y;
			update(1,1,n,id[x],id[x]+siz[x]-1,y);
		}
		else
		{
			cin>>x;
//			cout<<"aaaaaa"<<endl;
			cout<<query(1,1,n,id[x],id[x]+siz[x]-1)<<'\n';
		}
//		cout<<"---"<<m<<endl;
	}
	return 0;
}
