	{
		ans+=dfs(s,inf);
	}
	cout<<ans;
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=505;
int n,m,dfn[N],low[N],cnt,vis[N],vis2[N],cnt2,tmp,num,sum1,sum2;
vector<int> g[N];
void tarjan(int u,int f)
{
	low[u]=dfn[u]=++cnt;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		if(!dfn[v])
		{
			tarjan(v,u);
			low[u]=min(low[u],low[v]);
			if(low[v]>=dfn[u])
			{
				if(u!=tmp) vis2[u]=1;
				else cnt2++;
			}
		}
		else
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
}
void dfs(int u,int num)
{
	vis[u]=num;
	sum1++;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(vis2[v]&&vis[v]!=num)
		{
			sum2++;
			vis[v]=num;
		}
		if(!vis[v]) dfs(v,num);
	}
}
