const int N=3200005;
int n,m,k,ans,numm[N],ls[N],rs[N],tr1[N],tr2[N],sum[N];
void update(int u)
{
	tr1[u]=tr1[ls[u]]?tr1[ls[u]]:tr1[rs[u]];
	tr2[u]=tr2[rs[u]]?tr2[rs[u]]:tr2[ls[u]];
	sum[u]=sum[ls[u]]+sum[rs[u]]-(tr2[ls[u]]+1==tr1[rs[u]]);
}
void fun(int &num,int l,int r,int x)
{
	if(num==0)
	{
		k++;
		num=k;	
	}
	if(l==r)
	{
		tr1[num]=tr2[num]=x,sum[num]=1;
		return ;
	}
	int mid=(l+r)/2;
	if(x<=mid) fun(ls[num],l,mid,x);
	else fun(rs[num],mid+1,r,x);
	update(num);
}
void fun2(int &x,int &y,int l,int r)
{
	if(!x||!y)
	{
		x+=y;
		return ;
	}
	if(l==r)
	{
		tr1[x]=tr2[x]=l,sum[x]=1;
		return;
	}
	int mid=(l+r)/2;
	fun2(ls[x],ls[y],l,mid);
	fun2(rs[x],rs[y],mid+1,r);
	update(x);
}
