	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		add(u,v,w);
	}
	ll ans=0;
	while(bfs())
	{
		ans+=dfs(s,inf);
	}
	cout<<ans;
	return 0;
}

