#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=300005;
int n,m,s[N],f[N][25],sum[N][25],dep[N],mx,a[N],b[N],lc[N],num[N],cnt;
struct node
{
	int v,w;
};
vector<node> g[N];
void dfs(int x,int fa)
{
	dep[x]=dep[fa]+1;
	f[x][0]=fa;
	for(int i=0;i<g[x].size();i++)
	{
		int to=g[x][i].v;
		if(to==fa) continue;
		sum[to][0]=g[x][i].w;
		dfs(to,x);
	}
}
int lca(int x,int y)
{
	cnt=0;
	if(dep[y]<dep[x]) swap(x,y);
	int k=log2(dep[y])+1;
	for(int i=k;i>=0;i--)
	{
		if((dep[y]-(1<<i))>=dep[x])
		{
			cnt+=sum[y][i];
			y=f[y][i];
		}
	}
	if(x==y) return x;
	for(int i=k;i>=0;i--)
	{
		if(f[x][i]&&f[x][i]!=f[y][i])
		{
			cnt+=(sum[x][i]+sum[y][i]);
			x=f[x][i];
			y=f[y][i];
		}
	}
	cnt+=(sum[x][0]+sum[y][0]);
	return f[x][0];
}
void dfs2(int u)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==f[u][0]) continue;
		dfs2(v);
		s[u]+=s[v];
	}
}
bool check(int x)
{
	memset(s,0,sizeof(s));
	int cntt=0;
	for(int i=1;i<=m;i++)
	{
		if(num[i]>x)
		{
			cntt++;
			s[a[i]]++;
			s[b[i]]++;
			s[lc[i]]-=2;
		}
	}
	dfs2(1);
	for(int i=2;i<=n;i++)
	{
		if(sum[i][0]>=mx-x)
		{
			if(s[i]==cntt) return 1;
		}
	}
	return 0;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	int mxtmp=0;
	for(int i=1;i<n;i++)
	{
		int x,y,w;
		cin>>x>>y>>w;
		mxtmp=max(mxtmp,w);
		g[x].push_back(node{y,w});
		g[y].push_back(node{x,w});
	}
	dfs(1,0);
	for(int j=1;(1<<j)<=n;j++)
	{
		for(int i=1;i<=n;i++)
		{
			f[i][j]=f[f[i][j-1]][j-1];
			sum[i][j]=sum[i][j-1]+sum[f[i][j-1]][j-1];
		}
	}
	for(int i=1;i<=m;i++)
	{
		cin>>a[i]>>b[i];
		lc[i]=lca(a[i],b[i]);
		mx=max(mx,cnt);
		num[i]=cnt;
	}
	int l=mx-mxtmp,r=mx-1,mid;
	while(l<=r)
	{
		mid=(l+r)/2;
		if(check(mid))
		{
			r=mid-1;
		}
		else l=mid+1;
	}
	cout<<r+1;
	return 0;
}

