	}
	int l=-100,r=100;
	while(l<=r)
	{
		int mid=(l+r)/2;
		for(int i=1;i<=m;i++)
		{
			if(g[i].c==0) g[i].v+=mid;
		}
		for(int i=1;i<=n;i++) fa[i]=i;
		sum=0,cnt=0,cntwhite=0;
		kruskal();
		if(cntwhite>=need)
		{
			l=mid+1;
			ans=sum-need*mid;
		}
		else r=mid-1;
		for(int i=1;i<=m;i++)
		{
			if(g[i].c==0) g[i].v-=mid;
		}
	}
	cout<<ans;
	return 0;
}

