bool bfs()//顺便看一下图是不是联通的 
{
	for(int i=1;i<=n*m+2;i++)
	{
		lev[i]=inf;
		fir[i]=0;
	}
	queue<int> q;
	q.push(s);
	lev[s]=0;
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
			if((w>0)&&(lev[v]==inf))
			{
				q.push(v);
				lev[v]=lev[u]+1;
				if(v==t) return 1;
			}
		}
	}
	return 0;
}
ll dfs(int u,ll mn)//mn是目前找到的这条增广路的min 
{
	if(u==t) return mn;
	ll ans=0;
	for(int i=fir[u];i<g[u].size();i++)
	{
		fir[u]=i;
		int v=g[u][i].v,w=g[u][i].w;
		if((w>0)&&(lev[v]==lev[u]+1))
		{
			ll num=dfs(v,min(mn,(ll)w));
			if(num==0) lev[v]=inf;
			g[u][i].w-=num;
			g[v][g[u][i].fan].w+=num;//反向边
			ans+=num;
			mn-=num;
		}
	}
	return ans;
}
