#include<bits/stdc++.h> 
using namespace std;
const int N=100005;
struct node
{
	int sum0,sum1,len,llen0,rlen0,llen1,rlen1,tag,tag2,cnt0,cnt1;//tag : all 0(tag=1)/all 1(tag=2)  tag2:^   sum:最长连续1/0   cnt:总数 
} tr[4*N];
int n,m,a[N];
void change(int id)
{
	swap(tr[id].sum0,tr[id].sum1);
	swap(tr[id].llen0,tr[id].llen1);
	swap(tr[id].rlen0,tr[id].rlen1);
	swap(tr[id].cnt0,tr[id].cnt1);
}
void push_down(int id)
{
	if(tr[id].tag==0) goto nxt;
	tr[id*2].tag2=tr[id*2+1].tag2=0;
	if(tr[id].tag==1)//all 0
	{
		tr[id*2].tag=tr[id*2+1].tag=1;

		tr[id*2].sum1=tr[id*2].llen1=tr[id*2].rlen1=tr[id*2].cnt1=tr[id*2+1].cnt1=tr[id*2+1].sum1=tr[id*2+1].llen1=tr[id*2+1].rlen1=0;

		tr[id*2].sum0=tr[id*2].llen0=tr[id*2].rlen0=tr[id*2].cnt0=tr[id*2].len;
		tr[id*2+1].sum0=tr[id*2+1].llen0=tr[id*2+1].rlen0=tr[id*2+1].cnt0=tr[id*2+1].len;
	}
	else//all 1
	{
		tr[id*2].tag=tr[id*2+1].tag=2;

		tr[id*2].sum0=tr[id*2].llen0=tr[id*2].rlen0=tr[id*2].cnt0=tr[id*2+1].cnt0=tr[id*2+1].sum0=tr[id*2+1].llen0=tr[id*2+1].rlen0=0;

		tr[id*2].sum1=tr[id*2].llen1=tr[id*2].rlen1=tr[id*2].cnt1=tr[id*2].len;
		tr[id*2+1].sum1=tr[id*2+1].llen1=tr[id*2+1].rlen1=tr[id*2+1].cnt1=tr[id*2+1].len;
	}
	tr[id].tag=0;
	nxt: ;
	if(tr[id].tag2==1)
	{
		tr[id*2].tag2^=1;
		tr[id*2+1].tag2^=1;
		change(id*2);
		change(id*2+1);
	}
	tr[id].tag2=0;
}
void push_up(int id)
{
	//左边 
	if(tr[id*2].llen0==tr[id*2].len)//全0 
	{
		tr[id].llen0=tr[id*2].len+tr[id*2+1].llen0;
		tr[id].llen1=0;
	}
	else if(tr[id*2].llen1==tr[id*2].len) tr[id].llen1=tr[id*2].len+tr[id*2+1].llen1,tr[id].llen0=0;//全1
	else tr[id].llen0=tr[id*2].llen0,tr[id].llen1=tr[id*2].llen1;
	//右边 
	if(tr[id*2+1].rlen0==tr[id*2+1].len)//全0 
	{
		tr[id].rlen0=tr[id*2+1].len+tr[id*2].rlen0;
		tr[id].rlen1=0;
	}
	else if(tr[id*2+1].rlen1==tr[id*2+1].len) tr[id].rlen1=tr[id*2+1].len+tr[id*2].rlen1,tr[id].rlen0=0;//全1
	else tr[id].rlen0=tr[id*2+1].rlen0,tr[id].rlen1=tr[id*2+1].rlen1;
	tr[id].cnt0=tr[id*2].cnt0+tr[id*2+1].cnt0;
	tr[id].cnt1=tr[id*2].cnt1+tr[id*2+1].cnt1;
	tr[id].sum1=max(max(tr[id*2].sum1,tr[id*2+1].sum1),tr[id*2].rlen1+tr[id*2+1].llen1);
	tr[id].sum0=max(max(tr[id*2].sum0,tr[id*2+1].sum0),tr[id*2].rlen0+tr[id*2+1].llen0);
}
void build(int id,int l,int r)
{
	tr[id].tag=tr[id].tag2=0;
	tr[id].len=r-l+1;
	if(l==r)
	{
		if(a[l]==0)
		{
			tr[id].sum0=tr[id].llen0=tr[id].rlen0=1;
			tr[id].sum1=tr[id].llen1=tr[id].rlen1=0;
			tr[id].cnt0=1;
			tr[id].cnt1=0;

		}
		else
		{

			tr[id].sum0=tr[id].llen0=tr[id].rlen0=0;
			tr[id].sum1=tr[id].llen1=tr[id].rlen1=1;
			tr[id].cnt0=0;
			tr[id].cnt1=1;
		}
		return ;
	}
	int mid=(l+r)/2;
	build(id*2,l,mid);
	build(id*2+1,mid+1,r);
	push_up(id);
}
void update1(int id,int l,int r,int x,int y,int num)//all 0 / all 1
{
	if(r<x||y<l) return ;
	if(x<=l&&r<=y)
	{
		if(num==0)
		{
			tr[id].tag=1;
			tr[id].sum0=tr[id].llen0=tr[id].rlen0=tr[id].cnt0=tr[id].len;
			tr[id].sum1=tr[id].llen1=tr[id].rlen1=tr[id].cnt1=0;
		}
		else
		{
			tr[id].tag=2;
			tr[id].sum1=tr[id].llen1=tr[id].rlen1=tr[id].cnt1=tr[id].len;
			tr[id].sum0=tr[id].llen0=tr[id].rlen0=tr[id].cnt0=0;
		}
		tr[id].tag2=0;
		return ;
	}
	push_down(id);
	int mid=(l+r)/2;
	update1(id*2,l,mid,x,y,num);
	update1(id*2+1,mid+1,r,x,y,num);
	push_up(id);
}
void update2(int id,int l,int r,int x,int y)// ^=1
{
	if(r<x||y<l) return ;
	if(x<=l&&r<=y)
	{
		tr[id].tag2^=1;
		change(id);
		return ;
	}
	push_down(id);
	int mid=(l+r)/2;
	update2(id*2,l,mid,x,y);
	update2(id*2+1,mid+1,r,x,y);
	push_up(id);
}
int query1(int id,int l,int r,int x,int y)
{
	if(r<x||y<l) return 0;
	if(x<=l&&r<=y)
	{
		return tr[id].cnt1;
	}
	push_down(id);
	int mid=(l+r)/2;
	return query1(id*2,l,mid,x,y)+query1(id*2+1,mid+1,r,x,y);
}
int query2(int id,int l,int r,int x,int y)
{
	if(r<x||y<l) return 0;
	if(x<=l&&r<=y)
	{
		return tr[id].sum1;
	}
	push_down(id);
	int mid=(l+r)/2;
	int ans=0;
	if(mid>=x&&mid<=y) ans=min(mid-x+1,tr[id*2].rlen1)+min(y-mid,tr[id*2+1].llen1);
	return max(max(query2(id*2,l,mid,x,y),query2(id*2+1,mid+1,r,x,y)),ans);
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	build(1,1,n);
	while(m--)
	{
		int op,l,r;
		cin>>op>>l>>r;
		l++;
		r++;
		if(op==0)
		{
			update1(1,1,n,l,r,0);
		}
		else if(op==1)
		{
			update1(1,1,n,l,r,1);
		}
		else if(op==2)
		{
			update2(1,1,n,l,r);
		}
		else if(op==3)
		{
			cout<<query1(1,1,n,l,r)<<'\n';
		}
		else
		{
			cout<<query2(1,1,n,l,r)<<'\n';
		}
	}
	return 0;
}

