const int N=100005,M=1000005;
int n,m,a[N],mod;
int tot,tot2,dfn[N],low[N],chu[N],siz[N],ans,dp[N],dp2[N];
stack<int> st;
int vis[N],cnt,cnt2;
vector<int> g[N],g2[N];
map<int,map<int,bool> > mp; 
void tarjan(int u)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		cnt2++;
		int v;
		while(v=st.top())
		{
			vis[v]=0;
			a[v]=cnt2;
			siz[cnt2]++;
			st.pop();
			if(v==u) break;
		}
	}
}
void dfs(int x)
{
	dp2[x]=1;
	for(int i=0;i<g2[x].size();i++)
	{
		int v=g2[x][i];
		if(!dp[v]) dfs(v);
		if(dp[v]==dp[x]) dp2[x]=(dp2[x]+dp2[v])%mod;
		else if(dp[v]>dp[x])
		{
			dp[x]=dp[v];
			dp2[x]=dp2[v];
		}
	}
	dp[x]+=siz[x];
}
