		else if(op==2)
		{
			ll p=sum(1,1,n,l,r),q=r-l+1;
			ll gc=__gcd(p,q);
			p/=gc;
			q/=gc;
			cout<<p<<"/"<<q<<'\n';
		}
		else
		{
			ll sum1=sum(1,1,n,l,r);
