const int N=10005,M=50005,inf=0x3f3f3f3f;
struct node
{
	int u,v,w;
	bool operator<(const node other) const
	{
		return w>other.w;
	}
} a[M];
struct Node
{
	int v,w;
};
int fa[N],n,m,dep[N],f[N][25],mn[N][25],vis[N];
vector<Node> g[N];
int find(int x)
{
	if(fa[x]==x) return x;
	return fa[x]=find(fa[x]);
}
void dfs(int u,int ff,int w,int tmp)
{
	vis[u]=tmp;
	mn[u][0]=w;
	dep[u]=dep[ff]+1;
	f[u][0]=ff;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==ff) continue;
		dfs(v,u,g[u][i].w,tmp);
	}
}
int lca(int x,int y)
{
	if(dep[y]<dep[x]) swap(x,y);
	int k=log2(dep[y])+1,mnn=inf;
	for(int i=k;i>=0;i--)
	{
		if((dep[y]-(1<<i))>=dep[x])
		{
			mnn=min(mnn,mn[y][i]);
			y=f[y][i];
		}
	}
	if(x==y) return mnn;
	for(int i=k;i>=0;i--)
	{
		if(f[x][i]&&f[x][i]!=f[y][i])
		{
			mnn=min(mnn,mn[y][i]);
			mnn=min(mnn,mn[x][i]);
            x=f[x][i];
			y=f[y][i];

		}
	}
	return min(mnn,min(mn[x][0],mn[y][0]));
}
int main()
{
	ios::sync_with_stdio(false);
	cin.tie(0),cout.tie(0);
