		if(fu==fv) continue;
//		cout<<u<<"  --  "<<v<<"  w : "<<w<<"\n";
//		cout<<"YES\n";
		fa[fu]=fv;
		g[u].push_back(Node{v,w});
		g[v].push_back(Node{u,w});
	}
	int cnt=0;
	for(int i=1;i<=n;i++)
	{
		if(!vis[i])
		{
			cnt++;
			dfs(i,0,0,cnt);
		}
	}
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			f[j][i]=f[f[j][i-1]][i-1];
			mn[j][i]=min(mn[j][i-1],mn[f[j][i-1]][i-1]);
		}
	}
	int q;
