#define ll long long
const int N=350005;
struct node
{
	ll suma,sumb,laz;
} tr[N<<2];
ll n,m,a[N],b[N];
set<int> st;
void push_down(int l,int r,int u)
{
	if(!tr[u].laz) return;
	int mid=(l+r)/2;
	int ls=u*2,rs=u*2+1;
	tr[ls].sumb+=(mid-l+1)*tr[u].laz;
	tr[rs].sumb+=(r-mid)*tr[u].laz;
	tr[ls].laz+=tr[u].laz,tr[rs].laz+=tr[u].laz;
	tr[u].laz=0;
}
void push_up(int u)
{
	int ls=u*2,rs=u*2+1;
	tr[u].suma=tr[ls].suma+tr[rs].suma;
	tr[u].sumb=tr[ls].sumb+tr[rs].sumb;
}
void build(int l,int r,int u)
{
	if(l==r)
	{
		tr[u].suma=a[l];
		tr[u].sumb=b[l];
		return;
	}
	int ls=u*2,rs=u*2+1;
	int mid=(l+r)/2;
	build(l,mid,ls);
	build(mid+1,r,rs);
	push_up(u);
}
void update1(int l,int r,int u,int num,ll val)
{
	if(l==r&&l==num)
	{
		tr[u].suma+=val;
		return;
	}
	int ls=u*2,rs=u*2+1;
	int mid=(l+r)/2;
	if(num<=mid) update1(l,mid,ls,num,val);
	if(num>mid) update1(mid+1,r,rs,num,val);
	push_up(u);
}
ll query_a(int l,int r,int L,int R,int u)
{
	if(l<=L&&R<=r) return tr[u].suma;
	ll mid=(L+R)/2,sum=0;
	int ls=u*2,rs=u*2+1;
	if(l<=mid) sum+=query_a(l,r,L,mid,ls);
	if(r>mid) sum+=query_a(l,r,mid+1,R,rs);
	return sum;
}
void update2(int l,int r,int L,int R,int u,ll val)
{
	if(l<=L&&R<=r)
	{
		tr[u].sumb+=((R-L+1)*val);
		tr[u].laz+=val;
		return;
	}
	push_down(L,R,u);
	int mid=(L+R)/2;
	int ls=u*2,rs=u*2+1;
	if(l<=mid) update2(l,r,L,mid,ls,val);
	if(r>mid) update2(l,r,mid+1,R,rs,val);
	push_up(u);
}
ll query_b(ll num,int l,int r,int u)
{
	if(l==r&&l==num) return tr[u].sumb;
	push_down(l,r,u);
	int mid=(l+r)/2;
	int ls=u*2,rs=u*2+1;
	if(num<=mid) return query_b(num,l,mid,ls);
	if(num>mid) return query_b(num,mid+1,r,rs);
	return -1;
}
