		cin>>b[i];
	}
	for(int i=1;i<=n;i++)
	{
		if(a[i]>b[i]) st.insert(i);
	}
	build(1,n,1);
	while(m--)
	{
		ll op,l,r,val,add;
		cin>>op;
		if(op==1)
		{
			cin>>add>>val;
			update1(1,n,1,add,val);
			st.insert(add);
		}
		if(op==2)
		{
			cin>>l>>r;
