		}
		if(op==3)
		{
			cin>>l>>r>>val;
			update2(l,r,1,n,1,val);
		}
		if(op==4)
		{
			cin>>add;
			cout<<query_b(add,1,n,1)<<'\n';
		}
		if(op==5)
		{
			cin>>l>>r;
			auto it=st.lower_bound(l);
			while(it!=st.end())
			{
				int num=*it;
