const int N=50005;
int n,m,a[N],block,ans1[N],ans2[N],vis[N],anss;
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	int l,r,id;
	bool operator<(const node other) const
	{
		if(fun(l)!=fun(other.l)) return fun(l)<fun(other.l);
		return r<other.r;
	}
} q[N];
void add(int val)
{
	anss-=(vis[val]*(vis[val]-1)/2);
	vis[val]++;
	anss+=(vis[val]*(vis[val]-1)/2);
}
void del(int val)
{
	anss-=(vis[val]*(vis[val]-1)/2);
	vis[val]--;
	anss+=(vis[val]*(vis[val]-1)/2);
}
