		ans2[q[i].id]=(1ll*(rr-ll+1)*(rr-ll)/2);
		int tmp=__gcd(ans1[q[i].id],ans2[q[i].id]);
		ans1[q[i].id]/=tmp;
		ans2[q[i].id]/=tmp;
