					dp[i][j][k]=max(dp[i][j][k],dp[i+1][kk][k-j]+sum);
				}
//				cout<<i<<" "<<j<<" "<<k<<" "<<dp[i][j][k]<<"\n";
			}
			ans=max(ans,dp[i][j][m]);
		}
	}
	cout<<ans;
	return 0;
}

