#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
ll a[N],dp[N],n,m,sum,dq[N],dp2[N],dqs=1,dqt,mid,stl[N],lcnt,str[N],rcnt;
void pushl(ll num)
{
	if(!lcnt||dp2[stl[lcnt]]>dp2[num]) stl[++lcnt]=num;
}
void pushr(ll num)
{
	if(!rcnt||dp2[str[rcnt]]>dp2[num]) str[++rcnt]=num;
}
void rebuild()
{
	mid=(dqs+dqt)/2;
	lcnt=rcnt=0;
	for(ll i=mid;i>=dqs;i--)
	{
		pushl(i);
	}
	for(ll i=mid+1;i<=dqt;i++)
	{
		pushr(i);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(ll i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	ll pos=1;
	for(ll i=1;i<=n;i++)
	{
		sum+=a[i];
		while(sum>m)
		{
			sum-=a[pos];
			pos++;
		}
//		cout<<i<<" "<<sum<<"\n";
		while(dqs<=dqt&&a[dq[dqt]]<=a[i])
		{
//			cout<<dqs<<" "<<dqt<<" aaa\n";
			if(lcnt&&stl[lcnt]==dqt)
			{
//				cout<<"lcnt : "<<lcnt<<" -> "<<lcnt-1<<"  bbb(lcnt--)\n";
				lcnt--;
			}
			if(rcnt&&str[rcnt]==dqt)
			{
//				cout<<"rcnt : "<<rcnt<<" -> "<<rcnt-1<<"  ccc(rcnt--)\n";
				rcnt--;
			}
			dqt--;
//			cout<<"dqt--(ddd)\n";
			if(dqt<=mid)
			{
//				cout<<"-----rebuild()\n";
				rebuild();
			}
		}
		dq[++dqt]=i;
		if(dqs==dqt)
		{
			dp2[dqt]=dp[pos-1]+a[i];
		}
		else dp2[dqt]=dp[dq[dqt-1]]+a[i];
		pushr(dqt);
		if(stl[lcnt]==dqs) lcnt--;
		if(str[rcnt]==dqs) rcnt--;
		while(dqs<=dqt&&dq[dqs]<pos)
		{
			if(lcnt&&stl[lcnt]==dqs) lcnt--;
			if(rcnt&&str[rcnt]==dqs) rcnt--;
			dqs++;
			if(dqs>mid)
			{
				rebuild();
			}
		}
		dp[i]=a[dq[dqs]]+dp[pos-1];
		if(lcnt) dp[i]=min(dp[i],dp2[stl[lcnt]]);
		if(rcnt) dp[i]=min(dp[i],dp2[str[rcnt]]);
	}
	cout<<dp[n];
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
const long long N=300005;
struct node {
	long long s,a;
};
map<long long,node> mp;
long long tr[N*4],n,m;
node tag[N*4];
void push_down(long long x,long long l,long long r) {
	long long a=tag[x].a,s=tag[x].s;
	long long mid=(l+r)/2;
	tr[x*2]+=(1ll*(0ll+mid-l+1)*(s+s+(mid-l)*a)/2);//s为首项， s+(mid-l)*a为末项
	tr[x*2+1]+=(1ll*(0ll+r-mid)*(s+(mid-l+1)*a+s+(r-l)*a)/2);//s+(mid-l+1)*a为首项， s+(r-l)*a为末项
	tag[x*2].s+=tag[x].s;
	tag[x*2+1].s+=(s+(mid-l+1)*a);
	tag[x*2].a+=tag[x].a;
	tag[x*2+1].a+=tag[x].a;
	tag[x].a=tag[x].s=0;
}
void update(long long x,long long y,long long s,long long a,long long id,long long l,long long r) { //这里的s指信号最弱，而不是最强
	if(l>y||r<x) return ;
	if(x<=l&&y>=r) {
		tr[id]+=1ll*(0ll+r-l+1)*(s+(l-x)*a+s+(r-x)*a)/2;
//		cout<<"tr["<<id<<"]="<<tr[id]<<" l: "<<l<<" r: "<<r<<" s="<<s<<" a="<<a<<'\n';
		node t2=tag[id];
		tag[id]=node {t2.s+s+a*(l-x),t2.a+a};
		return ;
	}
	push_down(id,l,r);
	long long mid=(l+r)/2;
	update(x,y,s,a,id*2,l,mid);
	update(x,y,s,a,id*2+1,mid+1,r);
	tr[id]=tr[id*2]+tr[id*2+1];
}
long long query(long long x,long long y,long long id,long long l,long long r) {
	if(l>y||r<x) return 0;
	if(x<=l&&y>=r) {
//		cout<<"tr["<<id<<"]="<<tr[id]<<" l: "<<l<<" r: "<<r<<'\n';
		return tr[id];
	}
	push_down(id,l,r);
	long long mid=(l+r)/2;
	return query(x,y,id*2,l,mid)+query(x,y,id*2+1,mid+1,r);
}
int main() {
	cin>>n>>m;
	while(m--) {
		string s;
		cin>>s;
		if(s=="P") {
			long long x,s,a;
			cin>>x>>s>>a;
			//分成两个区间算
			mp[x]=node {s,a};
			long long t=s/a;
			long long leftl=max(1ll,x-t);//防止l<=0
			update(leftl,x,s%a+(a*(leftl-(x-t))),a,1,1,n);
			update(x+1,x+t,s-a,-a,1,1,n);
		}
		if(s=="U") {
			//把s和a都变成相反数
			long long x,s,a;
			cin>>x;
			s=mp[x].s,a=mp[x].a;
			long long t=s/a;
			long long leftl=max(1ll,x-t);//防止l<=0
			update(leftl,x,-s%a-(a*(leftl-(x-t))),-a,1,1,n);
			update(x+1,x+t,a-s,a,1,1,n);
		}
		if(s=="Z") {
			long long x,y;
			cin>>x>>y;
			cout<<query(x,y,1,1,n)/(y-x+1)<<'\n';
		}
	}
	return 0;
}
