#include <bits/stdc++.h>
using namespace std;
int t;
long long p,a;
vector<int> v;
long long quick_pow(long long a1,long long b,long long c)
{
    long long sum=1;
    while(b)
    {
        if(b&1) sum=(sum*a1)%c;
        b>>=1;
        a1=a1*a1;
        a1%=c;
    }
    return sum;
}
void prepare(long long num)
{
    v.clear();
    if(num%2==0)
    {
        v.push_back(2);
        v.push_back(num/2);
    }
    for(long long i=3;i<=num/i;i+=2)
    {
        if(num%i) continue;
        v.push_back(i);
        v.push_back(num/i);
    }
}
int main()
{
    cin>>t;
    while(t--)
    {
        cin>>a>>p;
        if(quick_pow(a,p-1,p)!=1)
        {
            cout<<"No\n";
            continue;
        }
        prepare(p-1);
        bool flag=1;
        for(auto i:v)
        {
            if(quick_pow(a,i,p)==1)
            {
                cout<<"No\n";
                flag=0;
                break;
            }
        }
        if(flag) cout<<"Yes\n";
    }
    return 0;
}

