template <typename T>void read(T &x) {
    x = 0;int f = 1;
    char ch = getchar();
    while (!isdigit(ch)) {if (ch == '-') f = -1;ch = getchar();}
    while (isdigit(ch)) {x = x * 10 + (ch ^ 48);ch = getchar();}
    x *= f;
    return;
}
void dfs(ll u,ll f)
{
	for(ll i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v;
		if(v==f) continue;
		dis[v]=dis[u]+g[u][i].w;
		dfs(v,u);
	}
}
bool dfs2(ll u,ll f)
{
	if(u==t)
	{
		vis[u]=1;
		return 1;
	}
	for(ll i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v;
		if(v==f) continue;
		if(dfs2(v,u))
		{
			vis[u]=1;
			return 1;
		}
	}
	return 0;
}
void dfs3(ll u,ll f)
{
	lcnt[u]=siz[u]=1;
	sum[u]=dep[u]=dep[f]+1;
	for(ll i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v;
		if(v==f) continue;
		dfs3(v,u);
		siz[u]+=siz[v];
		sum[u]+=sum[v];
		ll len=mx[v]+g[u][i].w;
		if(len>mx[u])
		{
			mx[u]=len;
			dcnt[u]=dcnt[v];
			lcnt[u]=lcnt[v];
		}
		else if(len==mx[u])
		{
			dcnt[u]+=dcnt[v];
			lcnt[u]++;
		}
	}
	dcnt[u]+=lcnt[u];
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	read(n);
	for(ll i=1;i<n;i++)
	{
		ll u,v,w;
		read(u);
		read(v);
		read(w);
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	dfs(1,0);
	for(ll i=1;i<=n;i++)
	{
		if(dis[i]>dis[s]) s=i;
	}
	dis[s]=0;
	dfs(s,0);
	for(ll i=1;i<=n;i++)
	{
		if(dis[i]>dis[t]) t=i;
	}
	dfs2(s,0);
	ll mid=0;
	for(ll i=1;i<=n;i++)
	{
//		cout<<vis[i]<<" ";
		if(vis[i]==0) continue;
//		cout<<i<<"  mid : "<<mid<<" dis  "<<dis[i]<<" "<<((dis[i]<=dis[t]/2)&&(dis[i]>dis[mid]))<<"\n";
		if((dis[i]<=dis[t]/2)&&(dis[i]>dis[mid])) mid=i;
	}
//	cout<<"\n"<<s<<" "<<t<<" "<<mid<<"\n";
	ll mx1=0,mx2=0,dcnt1=0,dcnt2=0,lcnt1=0,lcnt2=0;
	for(ll i=0;i<g[mid].size();i++)
	{
		ll v=g[mid][i].v;
		dfs3(v,mid);
		ll len=mx[v]+g[mid][i].w;
//		cout<<"v : "<<v<<"len : "<<len<<" dcnt[v] : "<<dcnt[v]<<" lcnt[v] : "<<lcnt[v]<<"\n";
		if(len>mx1)
		{
			mx2=mx1;
			dcnt2=dcnt1;
			lcnt2=lcnt1;
			mx1=len;
			dcnt1=dcnt[v];
			lcnt1=lcnt[v];
		}
		else if(len==mx1)
		{
			dcnt1+=dcnt[v];
			lcnt1+=lcnt[v];
		}
		else if(len>mx2)
		{
			mx2=len;
			dcnt2=dcnt[v];
			lcnt2=lcnt[v];
		}
		else if(len==mx2)
		{
			dcnt2+=dcnt[v];
			lcnt2+=lcnt[v];
		}
	}
	dcnt1+=lcnt1;
	dcnt2+=lcnt2;
	for(ll i=0;i<g[mid].size();i++)
	{	
		ll v=g[mid][i].v;
		if(mx[v]+g[mid][i].w==mx1&&lcnt[v]==lcnt1)
