#include <bits/stdc++.h>
using namespace std;
const int N=300005,mod=1e9+7;
long long t,n,k,niyuan[N],a[N],c[N],hou[N];//c[i] : C(k+i,i)
string s;
long long qp(long long x,int y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=(ans*x)%mod;
        }
        x=(x*x)%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    for(int i=1;i<=N-5;i++)
    {
        niyuan[i]=qp(i,mod-2);
    }
    cin>>t;
    while(t--)
    {
        cin>>n>>k>>s;
        hou[n+1]=0;
        s=" "+s;
        k--;
        long long ans=0;
        c[0]=1;
        for(int i=1;i<=n;i++)
        {
            c[i]=((c[i-1]*((i+k)%mod))%mod*niyuan[i])%mod;
            // cout<<c[i]<<" ";
        }
        // cout<<"\n";
        for(int i=1;i<n;i++)
        {
            a[i]=a[i-1]+(s[i]!=s[i+1]&&s[i]=='1');
            // cout<<a[i]<<" ";
        }
        // cout<<"\n";
        for(int i=n;i>1;i--)
        {
            if(s[i]=='1')
            {
                hou[i]=(hou[i+1]+(qp(2,a[i-2])*c[n-i])%mod)%mod;
            }
            else hou[i]=hou[i+1];
        }
        for(int i=1;i<n;i++)
        {
            if(s[i]=='0')
            {
                if(s[i+1]=='1') ans=(ans+(c[i-1]*c[n-i-1])%mod)%mod;
                ans=(ans+((qp(niyuan[2],a[i])*c[i-1])%mod)*(hou[i+2]+mod)%mod)%mod;
            }
        }
        cout<<ans<<"\n";
    }
    return 0;
}
