#include <bits/stdc++.h>
using namespace std;
const int N=1000005;
struct node
{
    int mod,pos;
    bool operator<(const node other) const 
    {
        if(mod==other.mod) return pos<other.pos;
        else return mod<other.mod;
    }
};
set<node> s[2];
int n,k;
long long ans;
string a,b;
int main()
{
    cin>>n>>k>>a>>b;
    a=" "+a;
    b=" "+b;
    for(int i=1;i<=n;i++)
    {
        if(a[i]==b[i]) continue;
        int t=a[i]-'0';
        if(s[!t].empty())
        {
            s[t].insert(node{i%k,i});
        }
        else
        {
            auto it=s[!t].lower_bound(node{i%k,0});
            if(it==s[!t].end())
            {
                it=s[!t].begin();
            }
            node t_node=*it;
            ans+=((i-t_node.pos-1)/k+1);
            s[!t].erase(it);
        }
    }
    cout<<ans;
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int c,t,n,m,fa[N],cnt;
string s;
bool vis[N*3];
int fun(int x)
{
	if(x==N-4||x==4-N) return x;
	if(vis[n-x+5]==1) return 0;
	if(x==0) return 0;
	if(vis[x+n+5]) return N-4;
	if(x<0&&(-x==fa[-x])) return x;
	if(x<0)
	{
		vis[x+n+5]=1;
		int tmp=fun(-fa[-x]);
		vis[x+n+5]=0;
		return tmp;
	}
	if(x==fa[x]) return x;
	vis[x+n+5]=1;
	fa[x]=fun(fa[x]);
	vis[x+n+5]=0;
	return fa[x];
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".out","w",stdout);
	cin>>c>>t;
	while(t--)
	{
		cnt=0;
		cin>>n>>m;
		for(int i=1;i<=n;i++)
		{
			fa[i]=i;
		}
		for(int i=1;i<=m;i++)
		{
			cin>>s;
			int x,y;
			cin>>x;
			if(s=="T")
			{
				fa[x]=N-4;
			}
			else if(s=="F")
			{
				fa[x]=4-N;
			}
			else if(s=="U")
			{
				fa[x]=0;
			}
			else
			{
				cin>>y;
				if(s=="+")
				{
					fa[x]=fa[y];
				}
				else fa[x]=-fa[y];
			}
		}
		for(int i=1;i<=n;i++)
		{
			if(fun(i)==0) cnt++;
		}
		cout<<cnt<<"\n";
	}
	return 0;
}

#include <bits/stdc++.h> 
using namespace std;
const int N=10005,K=105,inf=0x3f3f3f3f;
int n,m,k,vis[N][K];
struct node
{
	int v,w;
	bool operator<(const node other) const
	{
		return w>other.w;
	}
};
vector<node> g[N];
void bfs()
{
	memset(vis,0x3f,sizeof(vis));
	vis[1][0]=0;
	priority_queue<node> q;
	q.push(node{1,0});
	while(!q.empty())
	{
		node t=q.top();
		q.pop();
		int u=t.v,tim=t.w;
		if(u==n&&tim%k==0) return ;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
//			cout<<u<<" "<<v<<" : ";
//			if((w>tim)&&((w%k)!=(tim%k)))
//			{
//				cout<<"NO\n";
//				continue;
//			}
//			cout<<"YES\n";
			int nnum=((tim>=w)?(vis[u][tim%k]):(vis[u][tim%k]+(w-vis[u][tim%k]+k-1)/k*k))+1;
//			cout<<u<<" -> "<<v<<" "<<nnum<<'\n';
			if(vis[v][nnum%k]==inf) q.push(node{v,nnum});
			vis[v][nnum%k]=min(vis[v][nnum%k],nnum);
		}
	}
}
int main()
{
	cin>>n>>m>>k;
	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
	}
	bfs();
	if(vis[n][0]==inf) cout<<-1;
	else cout<<vis[n][0];
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=200005,mod=998244353;
int n,q;
ll dp[N][4],siz[N],ans;
struct node
{
	int v;
	ll w;
};
vector<node> g[N];
void dfs1(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==f) continue;
		dfs1(v,u);
		siz[u]+=siz[v];
	}
	siz[u]++;
}
void dfs2(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		ll w=g[u][i].w;
		if(v==f) continue;
		dp[v][0]=(siz[v]+1)*(n-siz[v])%mod*w*2%mod;
		dp[v][1]=siz[v]*(n-siz[v]+1)%mod*w*2%mod;
		dp[v][2]=(dp[v][0]+dp[u][2])%mod;
		dp[v][3]=(dp[v][1]+dp[u][3])%mod;
		ans=(ans+dp[v][1])%mod;
		dfs2(v,u);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>q;
	for(int i=1;i<n;i++)
	{
		int u,v;
		ll w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	dfs1(1,0);
	dfs2(1,0);
	while(q--)
	{
		int k;
		ll w;
		cin>>k>>w;
		cout<<(dp[k][2]+ans-dp[k][3]+2*n*w+mod)%mod<<"\n";
	}
	return 0;
}

