#include<bits/stdc++.h> 
using namespace std;
const int N=1000005;
string s;
int sumor,sumand,ans,lsor[N],lsand[N],lor[N],land[N];
void dfs(int l,int r)
{
//	cout<<l<<" "<<r<<" "<<s.substr(l,r-l+1)<<"\n";
	if(l==r)
	{
		ans=s[l]-'0';
		return ;
	}
	int lstor=lor[r],lstand=land[r];
	if(lstor<l) lstor=0;
	if(lstand<l) lstand=0;
	if(lstor>0)
	{
		dfs(l,lstor-1);
		if(ans==1)
		{
			sumor++;
			return ;
		}
		dfs(lstor+1,r);
		return ;
	}
	if(lstand>0)
	{
		dfs(l,lstand-1);
		if(ans==0)
		{
			sumand++;
			return ;
		}
		dfs(lstand+1,r);
		return ;
	}
	dfs(l+1,r-1);
}
int main()
{
	cin>>s;
	int tmp=0;
	for(int i=0;i<s.size();i++)
	{
		if(s[i]=='(') tmp++;
		else if(s[i]==')') tmp--;
		else
		{
			if(s[i]=='|') lsor[tmp]=i;
			else if(s[i]=='&') lsand[tmp]=i;
		}
		lor[i]=lsor[tmp];
		land[i]=lsand[tmp];
	}
	dfs(0,s.size()-1);
	cout<<ans<<"\n"<<sumand<<" "<<sumor;
	return 0;
}

