const int N=500005;
int n,m,dfn[N],low[N],cnt2;
vector<int> g[N],ans[N];
stack<int> st;
int vis[N],cnt;
void tarjan(int u,int f)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	int soncnt=0;
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			soncnt++;
			tarjan(v,u);
			low[u]=min(low[u],low[v]);
			if(low[v]>=dfn[u])
			{
				cnt2++;
				while(st.top()!=v)
				{
					ans[cnt2].push_back(st.top());
					st.pop();
				}
				ans[cnt2].push_back(st.top());
				st.pop();
				ans[cnt2].push_back(u);
			}
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(f==0&&soncnt==0)
	{
		cnt2++;
		ans[cnt2].push_back(u);
	}
}
