#define ll long long
const int N=10005,mod=1e9+7;
int n,cnt[30];
string s;
ll jc[N];
ll qp(ll x,ll y)
{
    ll ans=1;
    while(y)
    {
        if(y%2) ans=(ans*x)%mod;
        x=(x*x)%mod;
        y/=2;
    }
    return ans;
}
ll c(ll x,ll y)
{
    return jc[x]*qp((jc[x-y]%mod)*jc[y]%mod,mod-2)%mod;
}
int main()
{
	cin>>n>>s;
	jc[0]=1;
	for(int i=1;i<=n;i++)
	{
		jc[i]=jc[i-1]*i%mod;
