	}
	s=" "+s;
	for(int i=1;i<=n;i++)
	{
		cnt[s[i]-'a']++;
	}
	ll num=n/2,sum=1,flag=0,mx=(n%2==0)?0:1;
	for(int i=0;i<26;i++)
	{
		if(cnt[i]%2==1) flag++;
		if(flag>mx)
		{
			sum=0;
			break;
		}
		int t=cnt[i]/2;
		sum=(sum*c(num,t))%mod*jc[cnt[i]]%mod;
//		cout<<num<<" "<<t<<" "<<sum<<"\n";
		num-=t;
	}
	cout<<(jc[n]+mod-sum)%mod;
