    while(m--)
    {
        cin>>x>>y>>z;
        int t1=lca(x,y),t2=lca(y,z),t3=lca(x,z);
        if(t1==t2) t=t3;
        else if(t1==t3) t=t2;
        else t=t1;
        ans=deep[x]+deep[y]+deep[z]-(deep[t1]+deep[t2]+deep[t3]);
        cout<<t<<" "<<ans<<'\n';
    }
    return 0;
}

