int n,m,cnt,low[N],dfn[N],vis[N],ans;
vector<int> g[N];
stack<int> st;
void tarjan(int u)
{
	st.push(u);
	dfn[u]=low[u]=++cnt;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(!vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		bool flag=0;
		while(st.top()!=u)
		{
			flag=1;
			vis[st.top()]=1;
			st.pop();
		}
		ans+=flag;
		st.pop();
		vis[u]=1;
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int a,b;
		cin>>a>>b;
		g[a].push_back(b);
	}
	for(int i=1;i<=n;i++)
	{
		if(!dfn[i]) tarjan(i);
	}
	cout<<ans;
	return 0;
}

