    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            cin>>w[i][j];
        }
    }
    for(int i=1;i<=n;i++)
    {
        fun(w[i],mn[i],m,0);
        fun(w[i],mx[i],m,1);
    }
    for(int i=k;i<=m;i++)
    {
        int t1[N],t2[N],t3[N],t4[N];
        for(int j=1;j<=n;j++)
        {
            t1[j]=mx[j][i],t2[j]=mn[j][i];
        }
        fun(t1,t3,n,1);
        fun(t2,t4,n,0);
        for(int j=k;j<=n;j++) ans=min(ans,t3[j]-t4[j]);
    }
    cout<<ans;
    return 0;
}

