void dij()
{
	memset(dis,0x3f,sizeof(dis));
	while(!pq.empty()) pq.pop();
	dis[1]=0;
	ans[1]=1;
	pq.push(node{1,0});
	while(!pq.empty())
	{
		node t=pq.top();
		pq.pop();
		int u=t.u;
		ll w=t.w;
		if(vis[u]) continue;
		vis[u]=1;
		for(int i=0;i<g[u].size();i++)
		{
			Node tt=g[u][i];
			int v=tt.v,ww=tt.w;
			if(!vis[v]&&dis[u]+ww<dis[v])
			{
				dis[v]=dis[u]+ww;
				ans[v]=ans[u];
				pq.push(node{v,dis[v]});
			}
			else if(dis[u]+ww==dis[v])
			{
				ans[v]+=ans[u];
			}
		}
	}
}
