	while(m--)
	{
		ll op;
		cin>>op;
		if(op==1)
		{
			ll x,y,k;
			cin>>x>>y>>k;
			update(1,1,n,x,y,k);
		}
		else
		{
			ll x,y;
			cin>>x>>y;
			cout<<(x+y)*(y-x+1)/2+query(1,1,n,x,y)<<'\n';
		}
	}
	return 0;
}

