}
void dfs(int num,int fa)
{
    if(num>=n-m+1)
    {
        siz[num]=1;
        return ;
    }
    for(int i=head[num];i;i=e[i].nxt)
    {
        int x=e[i].id;
        if(x==fa) continue;
        dfs(x,num);
        siz[num]+=siz[x];
        for(int j=siz[num];j>-1;j--)
        {
            for(int k=0;k<=siz[x]&&k<=j;k++)
            {
                dp[num][j]=max(dp[num][j],dp[num][j-k]+dp[x][k]-e[i].w);
            }
        }
    }
}
