	for(int j=1;(1<<j)<=n;j++)
	{
		for(int i=1;i<=n;i++)
		{
			fa[i][j]=fa[fa[i][j-1]][j-1];
		}
	}
	while(q--)
	{
		int u,v;
		cin>>u>>v;
		int tmp=lca(u,v);
		a[u]++;
		a[v]++;
		a[tmp]--;
		a[fa[tmp][0]]--;
	}
	dfs2(1,0);
	int u,v;
	cin>>u>>v;
	int tmp=lca(u,v);
	while(u!=tmp)
	{
		if(a[u]==0) cnt++;
		u=fa[u][0];
	}
	while(v!=tmp)
	{
		if(a[v]==0) cnt++;
		v=fa[v][0];
	}
	if(a[u]==0) cnt++;
	cout<<cnt;
	return 0;
}

