		for(int i=1;i<=m;i++) cin>>p[i];
		for(int i=1;i<=n;i++)
		{
			if(a[i]>0)
			{
				int tmp;
				if(v[i]<=vv) tmp=(vv*vv-v[i]*v[i])/(2*a[i])+d[i];
				else tmp=d[i]-1;
				int l=1,r=m,mid;
				while(l<=r)
				{
					mid=(l+r)/2;
					if(p[mid]>tmp) r=mid-1;
					else l=mid+1;
				}
				if(r==m) continue;
				b[++cnt].l=r+1;
				b[cnt].r=m;
			}
