				{
					mid=(l+r)/2;
					if(p[mid]>=d[i]) r=mid-1;
					else l=mid+1;
				}
				if(r==m) continue;
				l=r+1,r=m;
				int tmp=l;
				while(l<=r)
				{
					mid=(l+r)/2;
					double tt=sqrt((double)v[i]*v[i]+(double)2*a[i]*(p[mid]-d[i]));
					if(tt>vv) l=mid+1;
					else r=mid-1;
				}
				if(l==tmp) continue;
				b[++cnt].l=tmp;
				b[cnt].r=l-1;
			}
		}
		sort(b+1,b+1+cnt);
