			mn=min(mn,b[i].r);
		}
		int ans=0,tmp2=0;
		for(int i=1;i<=cnt;i++)
		{
			if(vis[i]) vis[i]=0;
			else if(tmp2<b[i].l)
			{
				ans++;
				tmp2=b[i].r;
			}
		}
		cout<<cnt<<" "<<m-ans<<"\n";
	}
	return 0;
}

