void dij()
{
	priority_queue<node> pq;
	memset(ans,0x3f,sizeof(ans));
	ans[1]=0;
	pq.push(node{1,0});
	while(!pq.empty())
	{
		node t=pq.top();
		pq.pop();
		int u=t.v;
		if(vis[u]) continue;
		vis[u]=1;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].val;
			if(!vis[v]&&ans[u]+w<ans[v])
			{
				ans[v]=ans[u]+w;
				pq.push(node{v,ans[v]});
			}
		}
	}
}
