#include<bits/stdc++.h>
using namespace std;
int n,m1,m2,ans=0x3f3f3f3f;
vector<int> v[2];
void fun(int x)
{
    v[0].clear(),v[1].clear();
    for(int i=2;i<=sqrt(x)&&x>1;i+=((i==2)?1:2))
    {
        if(x%i>0) continue;
        int t=0;
        while(x%i==0) x/=i,t++;
        v[0].push_back(i);
        v[1].push_back(t);
    }
    if(x>1) v[0].push_back(x),v[1].push_back(1);
}
int main()
{
    cin>>n>>m1>>m2;
    fun(m1);
    vector<int> v1[2]={v[0],v[1]};
    while(n--)
    {
        int a;
        cin>>a;
        fun(a);
        double minn=0x3f3f3f3f;
        bool flag=true;
        for(int i=0;i<v1[0].size();i++)
        {
            auto t=lower_bound(v[0].begin(),v[0].end(),v1[0][i]);
            if(t==v[0].end()||*t!=v1[0][i])
            {
                flag=false;
                break;
            }
            minn=min(minn,(double)v[1][t-v[0].begin()]/(double)v1[1][i]);
        }
        if(!flag) continue;
        ans=min(ans,(int)ceil(m2/minn));
    }
    if(m1==1) cout<<0;
    else cout<<((ans==0x3f3f3f3f)?-1:ans);
    return 0;
}

