#include <bits/stdc++.h>
using namespace std;
const long long N=200005;
long long t,n,s[N],p[N],qian[N],hou[N],ans[N];
void delet(long long x)
{
    hou[qian[x]]=hou[x];
    qian[hou[x]]=qian[x];
}
long long get_time(long long x,long long y)
{
    return 2*(ceil(1.0*(p[y]-p[x])/(s[x]+s[y])))-(x%2);
}
struct node
{
    long long x,y,tim;
    bool operator<(const node other) const
    {
        return tim>other.tim;
    }
};
int main()
{
    cin>>t;
    while(t--)
    {
        memset(ans,0,sizeof(ans));
        priority_queue<node> q;
        cin>>n;
        for(long long i=1;i<=n;i++) cin>>p[i];
        for(long long i=1;i<=n;i++) cin>>s[i];
        for(long long i=1;i<n;i++)
        {
            qian[i]=i-1;
            hou[i]=i+1;
            q.push(node{i,i+1,get_time(i,i+1)});
        }
        qian[n]=n-1;
        hou[n]=n+1;
        while(!q.empty())
        {
            node t=q.top();
            q.pop();
            if(ans[t.x]||ans[t.y]) continue;
            ans[t.x]=ans[t.y]=t.tim;
            if(qian[t.x]>=1&&hou[t.y]<=n)
            {
                q.push(node{qian[t.x],hou[t.y],get_time(qian[t.x],hou[t.y])});
            }
            delet(t.x);
            delet(t.y);
        }
        for(long long i=1;i<=n;i++) cout<<ans[i]<<" ";
        cout<<"\n";
    }
    return 0;
}

