		g[y].push_back(x);
	}
	dfs(s,0);
	for(int j=1;(1<<j)<=n;j++)
	{
		for(int i=1;i<=n;i++)
		{
			f[i][j]=f[f[i][j-1]][j-1];
		}
	}
	while(m--)
	{
		int x,y;
		cin>>x>>y;
		cout<<lca(x,y)<<'\n';
	}  //上一个 AC 这里多了个 分号
