int dfs(int x,int y)
{
	if(b[y]<b[x]) swap(x,y);
	int ans=0;
	while(b[y]!=b[x])
	{
		y=fa[y];
		ans++;
	}
	while(x!=y)
	{
		ans+=2;
		x=fa[x];
		y=fa[y];
	}
	return ans;
}
