	{
        s.clear();
        sum=0;
		cin>>n;
		for(int i=1;i<=n;i++)
		{
			cin>>a[i];
			if(i==1)
			{
				sum+=a[i];
				s.insert(a[i]);
				continue;
			}
			set<int> ::iterator it=s.lower_bound(a[i]);
			if(it==s.end())
			{
				sum+=abs(a[i]-*(--it));
			}
			else if(*it!=a[i])
			{
				if(it!=s.begin())
                {
                    int t1=*it-a[i];
                    int t2=a[i]-(*--it);
                    int t3=min(t1,t2);
                    sum+=t3;
                }
				else sum+=(*it-a[i]);
			}
			s.insert(a[i]);
		}
		cout<<sum<<'\n';
	}
	return 0;
}

