string pluss(string a,string b)
{
    int sum[505]={0}, a1[505], b1[505]={0};
    reverse(a.begin(),a.end());
    reverse(b.begin(),b.end());
    for(int i=0;i<=a.size()-1;i++)
    {
        a1[i]=a[i]-48;
    }
    for(int i=0;i<=b.size()-1;i++)
    {
        b1[i]=b[i]-48;
    }
    int len=max(a.size(),b.size());
    for(int i=0;i<=len-1;i++)
    {
        sum[i]=a1[i]+b1[i]+sum[i];
        sum[i+1]=sum[i]/10;
        sum[i]=sum[i]%10;
    }
    while(sum[len]==0&&len>0)
    {
        len--;
    }
    string sum1="";
    for(int i=len;i>=0;i--)
    {
        sum1 += (sum[i]+'0');
    }
    return sum1;
}
string cheng(string a, string b) 
{
    int a1[105],b1[105],ji[210]={0};
    reverse(a.begin(),a.end());
    reverse(b.begin(),b.end());
    for(int i=0;i<=a.size()-1;i++)
    {
        a1[i]=a[i]-48;
    }
    for(int i=0;i<=b.size()-1;i++)
    {
        b1[i]=b[i]-48;
    }
    int len1=a.size(),len2=b.size();
    for(int i=0;i<=len1-1;i++)
    {
        for(int j=0;j<=len2-1;j++)
        {
            ji[i+j]=a1[i]*b1[j]+ji[i+j];
            ji[i+j+1]=ji[i+j]/10+ji[i+j+1];
            ji[i+j]%=10;
        }
    }
    int len=len1+len2;
    while(ji[len]==0&&len>0)
    {
        len--;
    }
    string ji1="";
    for(int i=len;i>=0;i--)
    {
        ji1+=(ji[i]+'0');
    }
    return ji1;
}

