	vis[x+1][y-2]=1;//标记一下马的控制点
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++) if((i!=1||j!=1)&&!vis[i][j]) step[i][j]=step[i-1][j]+step[i][j-1];//不能走进马的控制点
	cout<<step[n][m];
	return 0;
}

