#include <bits/stdc++.h>
using namespace std;
string s;
int cnt=0,pos[10],t;
bool flag;
bool prime(string s)
{
	int num=0;
	for(int i=0;i<s.size();i++)
	{
		num=num*10+(s[i]-'0');
	}
	if(num<=1) return 0;
	for(int i=2;i<=num/i;i++)
	{
		if(num%i==0) return 0;
	}
	return 1;
}
void dfs(int num,string s)
{
	if(flag) return ;
	if(num>cnt)
	{
		if(prime(s))
		{
			cout<<s;
			flag=1;
		}
		return ;
	}
	for(int i=0;i<=9;i++)
	{
		s[pos[num]]=i+'0';
		dfs(num+1,s);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--)
	{
		cin>>s;
		cnt=0;
		flag=0;
		for(int i=0;i<s.size();i++)
		{
			if(s[i]=='*')
			{
				pos[++cnt]=i;
			}
		}
		if(cnt==0)
		{
			if(prime(s)) cout<<s;
			else cout<<-1; 
		}
		else
		{
			dfs(1,s);
			if(!flag) cout<<-1;
		}
		cout<<'\n';
	}
	return 0;
}

