#define ll long long
const int N=200005;
int n,m,p,a[N],mx[N*4],mn[N*4],lst;
void pushup1(int u)
{
	mx[u]=max(mx[u*2],mx[u*2+1]);
}
int pushup2(int tmp,int u,int l,int r)
{
	if(l==r)
	{
		if(mx[u]<=tmp) return 1e9;
		else return tmp+l+1;
	}
	int mid=(l+r)/2;
	if(mx[u*2+1]<=tmp) return pushup2(tmp,u*2,l,mid);
	else return min(mn[u],pushup2(tmp,u*2+1,mid+1,r));
}
void update(int u,int l,int r,int x,int y)
{
	if(l==r&&l==x)
	{
		mx[u]=y-l;
		mn[u]=1e9;
		return ;
	}
	int mid=(l+r)/2;
	if(x<=mid) update(u*2,l,mid,x,y);
	else if(x>mid) update(u*2+1,mid+1,r,x,y);
	pushup1(u);
	mn[u]=pushup2(mx[u*2+1],u*2,l,mid);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
