	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		a[i+n]=a[i];
		update(1,1,n*2,i,a[i]);
		update(1,1,n*2,i+n,a[i]);
	}
//	cout<<"aaa"<<mx[1]<<" "<<mn[1]<<"\n";
	lst=min(1+mx[1],mn[1])+n-1;
	cout<<lst<<"\n";
	while(m--)
	{
		int x,y;
		cin>>x>>y;
		x^=(p*lst);
		y^=(p*lst);
		update(1,1,2*n,x,y);
		update(1,1,2*n,x+n,y);
//		cout<<"aaa"<<mx[1]<<" "<<mn[1]<<"\n";
		lst=min(1+mx[1],mn[1])+n-1;
		cout<<lst<<"\n";
	}
	return 0;
}

