const int mod=998244353,N=5005;
ll n,w[N],dp[N];
ll qp(ll x,ll y)
{
	y%=(mod-1);
	x%=mod;
	ll ans=1;
	while(y)
	{
		if(y%2==1) ans=(ans*x)%mod;
		x=(x*x)%mod;
		y/=2;
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
