	ll tot=0;
	for(int i=1;i<=n;i++)
	{
		cin>>w[i];
		tot+=w[i];
	}
	dp[0]=1;
	for(int i=2;i<=n;i++)
	{
		for(int j=tot;j>=w[i];j--)
		{
			dp[j]=(dp[j]-dp[j-w[i]]+mod)%mod;
		}
	}
	ll ans=0;
	for(int i=0;i<=tot-w[1];i++)
	{
		if(dp[i]==0) continue;
		ans=(ans+dp[i]*w[1]%mod*qp(w[1]+i,mod-2))%mod;
	}
	cout<<ans;
	return 0;
}

#include <bits/stdc++.h>
