	cin>>n>>k;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	for(int i=1;i<=n;i++)
	{
		cin>>c[i];
	}
	solve(getroot(1,0));
	cout<<ans;
	return 0;
}

