void tarjan(int u)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		cnt2++;
		int v;
		while(v=st.top())
		{
			vis[v]=0;
			id[v]=cnt2;
			siz[cnt2]++;
			st.pop();
			if(v==u) break;
		}
	}
}
bool fun(int num,char cc)
{
	char tmp=s[num];
	if(tmp=='c')
	{
		if(cc=='A') return 0;
		else return 1;
	}
	if(tmp=='b')
	{
		if(cc=='A') return 0;
		else return 1;
	}
	if(tmp=='a')
	{
		if(cc=='B') return 0;
		else return 1;
	}
	if(cc=='C') return 1;
	return 0;
}
char change(char cc)
{
	return cc-'a'+'A';
}
