				g[b[i]+n*(!flag2)].push_back(a[i]+n*(!flag1));
				mp[b[i]+n*(!flag2)]=1;
			}
		}
		for(int i=1;i<=2*n;i++)
		{
			if(!dfn[i]) tarjan(i);
		}
		bool flag=1;
		for(int i=1;i<=n;i++)
		{
			if(id[i]==id[i+n])
			{
				flag=0;
				break;
			}
		}
		if(!flag) goto end;
		for(int i=1;i<=n;i++)
