        a[cnt].x=x;
        a[cnt].low=y;
        a[cnt].high=yy;
        a[cnt].flag=1;
        vis[++cnt]=yy;
        a[cnt].x=xx;
        a[cnt].low=y;
        a[cnt].high=yy;
        a[cnt].flag=-1;
    }
    sort(vis+1,vis+cnt+1);
    int len=unique(vis+1,vis+1+cnt)-vis-1;
    for(int i=1;i<=cnt;i++)
    {
        int pos1=lower_bound(vis+1,vis+1+len,a[i].high)-vis;
        int pos2=lower_bound(vis+1,vis+1+len,a[i].low)-vis;
        val[pos1]=a[i].high;
        val[pos2]=a[i].low;
        a[i].high=pos1;
        a[i].low=pos2;
    }
    sort(a+1,a+1+cnt);
    for(int i=1;i<cnt;i++)
    {
        update(1,1,cnt,a[i].low,a[i].high-1,a[i].flag);
        ans+=((a[i+1].x-a[i].x)*tr[1].len);
    }
    cout<<ans;
    return 0;
}

