bool spfa()
{
	memset(dis,0x3f,sizeof(dis));
	dis[0]=0;
	queue<int> q;
	q.push(0);
	vis[0]=1;
	while(!q.empty()){
		int u=q.front();
		q.pop();
		vis[u]=0;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v;
			if(dis[v]>dis[u]+g[u][i].w)
			{
				dis[v]=dis[u]+g[u][i].w;
				if(!vis[v])
				{
					q.push(v);
					vis[v]=1;
					cnt[v]++;
					if(cnt[v]>n) return 0;
				}
			}
		}
	}
	return 1;
}
