#include <bits/stdc++.h>
using namespace std;
const long long N=100005,Max=1e10;
long long s[N],n,l,r,a[N],tot,root,ans;
struct node
{
	long long num,l,r;
};
node tr[3400005];
long long build()
{
	tot++;
	tr[tot].num=tr[tot].l=tr[tot].r=0;
	return tot;
}
void pushup(long long u)
{
	tr[u].num=tr[tr[u].l].num+tr[tr[u].r].num;
}
void add(long long i,long long x,long long y,long long j)
{
	if(x>j||y<j) return ;
	if(x==y)
	{
		tr[i].num++;
		return ;
	}
	if(!tr[i].l)
	{
		tr[i].l=build();
	}
	if(!tr[i].r)
	{
		tr[i].r=build();
	}
	long long mid=(x+y)>>1;
	add(tr[i].l,x,mid,j);
	add(tr[i].r,mid+1,y,j);
	pushup(i);
}
long long sum(long long i,long long x,long long y,long long x1,long long y1)
{
	if(x>y1||y<x1) return 0;
	if(x>=x1&&y<=y1) return tr[i].num;
	long long mid=(x+y)>>1;
	if(!tr[i].l)
	{
		tr[i].l=build();
	}
	if(!tr[i].r)
	{
		tr[i].r=build();
	}
	return sum(tr[i].l,x,mid,x1,y1)+sum(tr[i].r,mid+1,y,x1,y1);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>l>>r;
	for(long long i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	root=build();
	add(root,-Max,Max,0);
	for(long long i=1;i<=n;i++)
	{
		s[i]+=a[i]; 
		ans+=sum(root,-Max,Max,s[i]-r,s[i]-l);
		add(root,-Max,Max,s[i]);
	}
	cout<<ans;
	return 0;
}

