const int N=3005;
int tim,dfn[N],low[N],cnt,vis[N],n,m,p,chu[N],ru[N],a[N],vis2[N],vis3[N],vis4[N],ans,minn=0x3f3f3f3f,flag[N];
bool flag2[N];
vector<int> G[N],g[N],g2[N];
map<int,int> mapp;
stack<int> st;
void tarjan(int u)
{
	dfn[u]=low[u]=++tim;
	st.push(u);
	for(int i=0;i<G[u].size();i++)
    {
		int v=G[u][i];
		if(dfn[v]==0)
        {
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v]==0)
        {
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
    {
		cnt++;
		while(true)
        {
			int now=st.top();
			st.pop();
			vis[now]=cnt;


            if(mapp.count(now))
            {
                vis4[cnt]+=mapp[now];
                vis3[cnt]=min(vis3[cnt],now);
            }
            else vis2[cnt]=1; 
			if(now==u) break;
		}
	}
}
void topo()
{
    queue<int> q;
    for(int i=1;i<=cnt;i++)
    {
        if(ru[i]==0)
        {
            q.push(i);
            ans+=vis4[i];
            if(vis2[i])
            {
                minn=min(minn,vis3[i]);
                flag[i]=0;
            }
        }
    }
    while(!q.empty())
    {
        int u=q.front();
        q.pop();
        if(ru[u]==0)
        {
            flag[u]=1;
            goto a;
        }
        flag[u]=0;
        for(int i=0;i<g2[u].size();i++)
        {
            int v=g2[u][i];
            if(flag[v]==1)
            {
                flag[u]=1;
                break;
            }
        }
        if(flag[u]==0) minn=min(minn,vis3[u]);
        a: ;
        for(int i=0;i<g[u].size();i++)
        {
            int v=g[u][i];
            if(flag2[v]==0) q.push(v);
            flag2[v]=1;
        }
    }
}
