int n,a[N],b[N];
ull has[N],tmp[N];
ull hasnum(int l,int r)
{
	return has[r]-has[l-1]*tmp[r-l+1];
}
int fun(int x,int y)
{
	int l=-1,r=min(n-x+1,n-y+1)+1;
	while(l<=r)
	{
		int mid=(l+r)/2;
		if(hasnum(x,x+mid-1)==hasnum(y,y+mid-1)) l=mid+1;
		else r=mid-1;
	}
	return l-1;
}
bool cmp(int x,int y)
{
	int num=fun(x,y);
	return s[x+num]<s[y+num];
}
