using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=305;
const ll inf=1e17;
ll n,s,dep[N],mx,mxid,tl,tr,num,f[N][25],dep2[N],ww[N],vis[N];
struct node
{
	ll v,w;
};
vector<node> g[N];
void dfs(int u,int fa)
{
	dep2[u]=dep2[fa]+1;
	f[u][0]=fa;
	if(dep[u]>mx)
	{
		mx=dep[u];
		mxid=u;
	}
	for(int i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v,w=g[u][i].w;
		if(v==fa) continue;
		dep[v]=dep[u]+w;
		dfs(v,u);
		ww[v]=w;
	}
}
void prepare()
{
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			f[j][i]=f[f[j][i-1]][i-1];
		}
	}
}
int lca(int x,int y)
{
	if(dep2[y]<dep2[x]) swap(x,y);
	int k=log2(dep2[y])+1;
	for(int i=k;i>=0;i--)
	{
		if((dep2[y]-(1<<i))>=dep2[x]) y=f[y][i];
	}
	if(x==y) return x;
	for(int i=k;i>=0;i--)
	{
		if(f[x][i]&&f[x][i]!=f[y][i])
		{
			x=f[x][i];
			y=f[y][i];
		}
	}
	return f[x][0];
}
int up(int u,ll x)
{
	ll tmp=0;
	while(u!=tl&&tmp+ww[u]<=x)
	{
		tmp+=ww[u];
		u=f[u][0];
	}
	return u;
}
ll sum;
ll fun(int u,ll x)
{
	for(int i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v,w=g[u][i].w;
		if(vis[v])
		{
			if(v==f[u][0]) continue;
			sum+=w;
			if(sum>x) return u;
			else return fun(v,x);
		}
	}
}
bool check(int x)
{
	sum=0;
	ll tmp1=fun(tl,x),tmp2=up(tr,x);
	return (dep[tmp2]-dep[tmp1]<=s);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>s;
	for(int i=1;i<n;i++)
	{
		ll x,y,w;
		cin>>x>>y>>w;
		g[x].push_back(node{y,w});
		g[y].push_back(node{x,w});
	}
	dfs(1,0);
	mx=0;
	tl=mxid;
	dep[mxid]=0;
	dfs(mxid,0);
	tr=mxid;
	num=mx;
	ll l=inf,r=num;
	prepare();
	int tmp=tr;
	while(tmp)
	{
//		cout<<tmp<<" ";
		vis[tmp]=1;
		tmp=f[tmp][0];
	}
	for(int i=1;i<=n;i++)
	{
//		cout<<vis[i]<<" ";
		if(!vis[i])
		{
//			cout<<i<<" : "<<lca(i,tr)<<" "<<dep[i]-dep[lca(i,tr)]<<"\n";
			l=min(l,dep[i]-dep[lca(i,tr)]);
		}
	}
//	cout<<"\n"<<tl<<" "<<tr<<" "<<num<<" "<<l<<" "<<r<<endl;
	while(l<=r)
	{
		ll mid=(l+r)/2;
		if(check(mid)) r=mid-1;
		else l=mid+1;
	}
	cout<<l;
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
const int INF=0x3f3f3f3f+1;
double d_1,c,d_2,d[10],p[10],num=0,sum;
int n;
int main()
{
	cin>>d_1>>c>>d_2>>p[0]>>n;
	d[0]=0;
	for(int i=1;i<=n;i++)
	{
		cin>>d[i]>>p[i]; 
	}
	d[n+1]=d_1;
	p[n+1]=INF;
	for(int i=0;i<=n;)
	{
		double t=c*d_2,mn=0x3f3f3f3f+10;
		int id;
		for(int j=i+1;d[j]<=t+d[i];j++)
		{
			if(mn>p[j])
			{
				mn=p[j];
				id=j;
			}
			if(j==n+1) break;
		}
		if(mn==0x3f3f3f3f)
		{
			cout<<"No Solution";
			return 0;
		}
		if(mn<p[i]||mn==INF)
		{
			double need=(d[id]-d[i])/d_2;
			if(num>=need)
			{
				i=id;
				num-=need;
				continue;
			}
			sum+=((need-num)*p[i]);
			num=0;
			i=id;
			continue;
		}
		sum+=(c-num)*p[i];
		num=c-(d[id]-d[i])/d_2;
		i=id;
	}
	cout<<fixed<<setprecision(2)<<sum;
	return 0;
}

#include <iostream>
#include <stack>
using namespace std;
stack<char> a;
int main()
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        string s;
        cin>>s;
        bool flag=true;
        for(int j=0;j<=s.size()-1;j++)
        {
            if(s[j]=='(')
            {
                a.push(')');
            }
            else if(s[j]=='[')
            {
                a.push(']');
            }
            else if(s[j]==')'||s[j]==']')
            {
                if(a.empty()||a.top()!=s[j])
                {
                    flag=false;
                    break;
                }
                else
                {
                    a.pop();
                }
            }
        }
        if(flag&&a.empty())
        {
            cout<<"Yes"<<endl;
        }
        else
        {
            cout<<"No"<<endl;
            while(!(a.empty()))
            {
                a.pop();
            }
        }
    }
    return 0;
}
